+codeunit 148185 "Sustainability Calc. Mgt. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit "Assert";
+        LibrarySustainability: Codeunit "Library - Sustainability";
+        LibraryERM: Codeunit "Library - ERM";
+
+    [Test]
+    procedure TestGetCollectableGLAmountReturnsPositiveForNegativeBalance()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        CollectedAmount: Decimal;
+        NegativeAmount: Decimal;
+        CategoryCode: Code[20];
+    begin
+        // [SCENARIO] Custom Amount from G/L Entries should always be positive regardless of the sign of G/L Entry amounts
+        // This test validates that the GetCollectableGLAmount function returns an absolute value.
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account with negative balance (credit entries)
+        LibraryERM.CreateGLAccount(GLAccount);
+        NegativeAmount := -52818.18;
+        CreateGLEntry(GLAccount."No.", NegativeAmount, WorkDate());
+
+        // [GIVEN] A Sustainability Account Category with "Calculate from General Ledger" enabled and G/L Account Filter set
+        CategoryCode := 'TESTGLNEG';
+        SustainAccountCategory := LibrarySustainability.InsertAccountCategory(
+            CategoryCode,
+            'Test Category for Negative Balance',
+            Enum::"Emission Scope"::"Scope 3",
+            Enum::"Calculation Foundation"::Custom,
+            true, false, false, 'Test Value', true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Modify(true);
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, 0D, 0D);
+
+        // [THEN] The returned amount should be positive (absolute value)
+        Assert.IsTrue(CollectedAmount > 0, 'Custom Amount should be positive when collected from G/L Entries');
+        Assert.AreEqual(Abs(NegativeAmount), CollectedAmount, 'Custom Amount should be the absolute value of the G/L Entry amount');
+    end;
+
+    [Test]
+    procedure TestGetCollectableGLAmountReturnsPositiveForPositiveBalance()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        CollectedAmount: Decimal;
+        PositiveAmount: Decimal;
+        CategoryCode: Code[20];
+    begin
+        // [SCENARIO] Custom Amount from G/L Entries should remain positive when G/L Entry amounts are positive
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account with positive balance (debit entries)
+        LibraryERM.CreateGLAccount(GLAccount);
+        PositiveAmount := 52818.18;
+        CreateGLEntry(GLAccount."No.", PositiveAmount, WorkDate());
+
+        // [GIVEN] A Sustainability Account Category with "Calculate from General Ledger" enabled and G/L Account Filter set
+        CategoryCode := 'TESTGLPOS';
+        SustainAccountCategory := LibrarySustainability.InsertAccountCategory(
+            CategoryCode,
+            'Test Category for Positive Balance',
+            Enum::"Emission Scope"::"Scope 3",
+            Enum::"Calculation Foundation"::Custom,
+            true, false, false, 'Test Value', true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Modify(true);
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, 0D, 0D);
+
+        // [THEN] The returned amount should be positive
+        Assert.IsTrue(CollectedAmount > 0, 'Custom Amount should be positive when collected from G/L Entries');
+        Assert.AreEqual(PositiveAmount, CollectedAmount, 'Custom Amount should equal the G/L Entry amount');
+    end;
+
+    [Test]
+    procedure TestGetCollectableGLAmountWithMultipleEntriesNegativeSum()
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        GLAccount: Record "G/L Account";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        CollectedAmount: Decimal;
+        Amount1, Amount2, Amount3 : Decimal;
+        ExpectedAmount: Decimal;
+        CategoryCode: Code[20];
+    begin
+        // [SCENARIO] Custom Amount from multiple G/L Entries with negative net sum should be positive
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account with multiple entries resulting in negative net balance
+        LibraryERM.CreateGLAccount(GLAccount);
+        Amount1 := 10000.00;
+        Amount2 := -35000.00;
+        Amount3 := -27818.18;
+        CreateGLEntry(GLAccount."No.", Amount1, WorkDate());
+        CreateGLEntry(GLAccount."No.", Amount2, WorkDate());
+        CreateGLEntry(GLAccount."No.", Amount3, WorkDate());
+        ExpectedAmount := Abs(Amount1 + Amount2 + Amount3);
+
+        // [GIVEN] A Sustainability Account Category with "Calculate from General Ledger" enabled
+        CategoryCode := 'TESTGLMUL';
+        SustainAccountCategory := LibrarySustainability.InsertAccountCategory(
+            CategoryCode,
+            'Test Category for Multiple Entries',
+            Enum::"Emission Scope"::"Scope 3",
+            Enum::"Calculation Foundation"::Custom,
+            true, false, false, 'Test Value', true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccount."No.");
+        SustainAccountCategory.Modify(true);
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, 0D, 0D);
+
+        // [THEN] The returned amount should be positive (absolute value of the sum)
+        Assert.IsTrue(CollectedAmount > 0, 'Custom Amount should be positive when collected from G/L Entries');
+        Assert.AreEqual(ExpectedAmount, CollectedAmount, 'Custom Amount should be the absolute value of the sum of G/L Entry amounts');
+    end;
+
+    local procedure CreateGLEntry(GLAccountNo: Code[20]; Amount: Decimal; PostingDate: Date)
+    var
+        GLEntry: Record "G/L Entry";
+        EntryNo: Integer;
+    begin
+        GLEntry.Reset();
+        if GLEntry.FindLast() then
+            EntryNo := GLEntry."Entry No." + 1
+        else
+            EntryNo := 1;
+
+        GLEntry.Init();
+        GLEntry."Entry No." := EntryNo;
+        GLEntry."G/L Account No." := GLAccountNo;
+        GLEntry.Amount := Amount;
+        GLEntry."Posting Date" := PostingDate;
+        GLEntry."Document No." := 'TEST' + Format(EntryNo);
+        GLEntry.Insert();
+    end;
+}

