+codeunit 134893 "Batch Post Sales Currency Test"
+{
+    // [FEATURE] [Batch Post] [Sales] [Currency]
+    // Test for batch posting sales invoices with currency code and replace posting date.
+    // Verifies that line amounts are preserved and lines are not recreated.
+
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryERM: Codeunit "Library - ERM";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('RequestPageHandlerBatchPostSalesInvoices,MessageHandler')]
+    [Scope('OnPrem')]
+    procedure BatchPostSalesInvoiceWithCurrencyAndReplacePostingDatePreservesLineAmount()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        SalesInvoiceLine: Record "Sales Invoice Line";
+        LibraryJobQueue: Codeunit "Library - Job Queue";
+        CurrencyCode: Code[10];
+        OriginalPostingDate: Date;
+        NewPostingDate: Date;
+        OriginalUnitPrice: Decimal;
+        OriginalAmount: Decimal;
+    begin
+        // [SCENARIO] Batch posting sales invoice with currency code and Replace Posting Date should preserve line amounts
+        // [FEATURE] [Sales] [Batch Post] [Currency] [Replace Posting Date]
+        Initialize();
+
+        LibrarySales.SetPostWithJobQueue(true);
+        BindSubscription(LibraryJobQueue);
+        LibraryJobQueue.SetDoNotHandleCodeunitJobQueueEnqueueEvent(true);
+
+        // [GIVEN] A currency with exchange rates for original and new posting dates
+        OriginalPostingDate := WorkDate();
+        NewPostingDate := CalcDate('<1M>', WorkDate());
+        CurrencyCode := CreateCurrencyWithMultipleDatesExchRates(OriginalPostingDate, NewPostingDate);
+
+        // [GIVEN] A sales invoice with Currency Code set and a specific unit price
+        OriginalUnitPrice := LibraryRandom.RandDecInRange(100, 500, 2);
+        CreateSalesInvoiceWithCurrency(SalesHeader, SalesLine, CurrencyCode, OriginalUnitPrice);
+        SalesHeader."Posting Date" := OriginalPostingDate;
+        SalesHeader.Modify();
+
+        OriginalAmount := SalesLine.Amount;
+
+        // [WHEN] Batch Post Sales Invoice with Replace Posting Date option to a different date
+        RunBatchPostSalesInvoice(SalesHeader."No.", NewPostingDate);
+        LibraryJobQueue.FindAndRunJobQueueEntryByRecordId(SalesHeader.RecordId);
+
+        // [THEN] Posted Sales Invoice exists with the new posting date
+        SalesInvoiceHeader.SetRange("Pre-Assigned No.", SalesHeader."No.");
+        Assert.RecordIsNotEmpty(SalesInvoiceHeader);
+        SalesInvoiceHeader.FindFirst();
+        SalesInvoiceHeader.TestField("Posting Date", NewPostingDate);
+
+        // [THEN] Posted Sales Invoice Line has the same Unit Price and Amount as the original sales line
+        SalesInvoiceLine.SetRange("Document No.", SalesInvoiceHeader."No.");
+        SalesInvoiceLine.FindFirst();
+        Assert.AreEqual(OriginalUnitPrice, SalesInvoiceLine."Unit Price", 'Unit Price should be preserved after batch posting with Replace Posting Date');
+        Assert.AreEqual(OriginalAmount, SalesInvoiceLine.Amount, 'Line Amount should be preserved after batch posting with Replace Posting Date');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Batch Post Sales Currency Test");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Batch Post Sales Currency Test");
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        isInitialized := true;
+        LibrarySetupStorage.SaveSalesSetup();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Batch Post Sales Currency Test");
+    end;
+
+    local procedure CreateCurrencyWithMultipleDatesExchRates(OriginalDate: Date; NewDate: Date): Code[10]
+    var
+        CurrencyCode: Code[10];
+        ExchRateAmount: Decimal;
+    begin
+        // Create currency with GL account setup
+        CurrencyCode := LibraryERM.CreateCurrencyWithGLAccountSetup();
+
+        // Create exchange rate for original date
+        ExchRateAmount := LibraryRandom.RandDecInRange(1, 2, 2);
+        LibraryERM.CreateExchangeRate(CurrencyCode, OriginalDate, ExchRateAmount, ExchRateAmount);
+
+        // Create exchange rate for new date (slightly different rate to simulate real scenario)
+        ExchRateAmount := LibraryRandom.RandDecInRange(1, 2, 2);
+        LibraryERM.CreateExchangeRate(CurrencyCode, NewDate, ExchRateAmount, ExchRateAmount);
+
+        exit(CurrencyCode);
+    end;
+
+    local procedure CreateSalesInvoiceWithCurrency(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; CurrencyCode: Code[10]; UnitPrice: Decimal)
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader.Validate("Currency Code", CurrencyCode);
+        SalesHeader.Modify(true);
+
+        LibraryInventory.CreateItem(Item);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(1, 10));
+        SalesLine.Validate("Unit Price", UnitPrice);
+        SalesLine.Modify(true);
+    end;
+
+    local procedure RunBatchPostSalesInvoice(DocumentNoFilter: Text; PostingDate: Date)
+    var
+        SalesHeader: Record "Sales Header";
+    begin
+        UpdateCalcInvDiscSalesReceivablesSetup(false);
+        LibraryVariableStorage.Enqueue(DocumentNoFilter);
+        LibraryVariableStorage.Enqueue(PostingDate);
+
+        Commit();
+        Report.RunModal(Report::"Batch Post Sales Invoices", true, true, SalesHeader);
+    end;
+
+    local procedure UpdateCalcInvDiscSalesReceivablesSetup(CalcInvDisc: Boolean)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Calc. Inv. Discount", CalcInvDisc);
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    [RequestPageHandler]
+    [Scope('OnPrem')]
+    procedure RequestPageHandlerBatchPostSalesInvoices(var BatchPostSalesInvoices: TestRequestPage "Batch Post Sales Invoices")
+    var
+        SalesHeader: Record "Sales Header";
+        PostingDate: Variant;
+        DocumentNoFilter: Variant;
+        RunReplacePostingDate: Boolean;
+    begin
+        LibraryVariableStorage.Dequeue(DocumentNoFilter);
+        LibraryVariableStorage.Dequeue(PostingDate);
+
+        BatchPostSalesInvoices."Sales Header".SetFilter("No.", DocumentNoFilter);
+        BatchPostSalesInvoices."Sales Header".SetFilter("Document Type", Format(SalesHeader."Document Type"::Invoice));
+
+        BatchPostSalesInvoices.PostingDate.SetValue(PostingDate);
+        RunReplacePostingDate := Format(PostingDate) <> '';
+        BatchPostSalesInvoices.ReplaceDocumentDate.SetValue(RunReplacePostingDate);
+        BatchPostSalesInvoices.ReplacePostingDate.SetValue(RunReplacePostingDate);
+        BatchPostSalesInvoices.OK().Invoke();
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+    end;
+}

