+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Inventory.Transfer;
+
+using Microsoft.Inventory.Setup;
+using Microsoft.Inventory.Item;
+using Microsoft.Warehouse.Request;
+
+codeunit 137039 "Transfer Order Variant Mand."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    procedure ReleaseTransferOrderWithoutVariantCodeWhenVariantMandatory()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        InventorySetup: Record "Inventory Setup";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        InTransitLocation: Record Location;
+    begin
+        // [SCENARIO] When releasing a Transfer Order for an item with variants and "Variant Mandatory if Exists" enabled,
+        // the system should error if Variant Code is not specified on the Transfer Line.
+
+        // [GIVEN] Initialize test
+        Initialize();
+
+        // [GIVEN] Inventory Setup with "Variant Mandatory if Exists" enabled
+        InventorySetup.Get();
+        InventorySetup.Validate("Variant Mandatory if Exists", true);
+        InventorySetup.Modify(true);
+
+        // [GIVEN] An item with variants available
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateVariant(ItemVariant, Item);
+
+        // [GIVEN] Locations for Transfer Order
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationFrom);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] A Transfer Order with a line without Variant Code specified
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandDecInRange(1, 10, 2));
+
+        // [WHEN] Try to release the Transfer Order
+        // [THEN] An error is thrown because Variant Code is mandatory for the item
+        asserterror LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+        Assert.ExpectedError('Variant Code');
+    end;
+
+    [Test]
+    procedure ReleaseTransferOrderWithVariantCodeWhenVariantMandatory()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        InventorySetup: Record "Inventory Setup";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        InTransitLocation: Record Location;
+    begin
+        // [SCENARIO] When releasing a Transfer Order for an item with variants and "Variant Mandatory if Exists" enabled,
+        // the system should release successfully if Variant Code is specified on the Transfer Line.
+
+        // [GIVEN] Initialize test
+        Initialize();
+
+        // [GIVEN] Inventory Setup with "Variant Mandatory if Exists" enabled
+        InventorySetup.Get();
+        InventorySetup.Validate("Variant Mandatory if Exists", true);
+        InventorySetup.Modify(true);
+
+        // [GIVEN] An item with variants available
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateVariant(ItemVariant, Item);
+
+        // [GIVEN] Locations for Transfer Order
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationFrom);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] A Transfer Order with a line WITH Variant Code specified
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandDecInRange(1, 10, 2));
+        TransferLine.Validate("Variant Code", ItemVariant.Code);
+        TransferLine.Modify(true);
+
+        // [WHEN] Release the Transfer Order
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] Transfer Order is released successfully
+        TransferHeader.Get(TransferHeader."No.");
+        Assert.AreEqual(TransferHeader.Status::Released, TransferHeader.Status, 'Transfer Order should be released.');
+    end;
+
+    [Test]
+    procedure ReleaseTransferOrderWithoutVariantCodeWhenVariantNotMandatory()
+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        InventorySetup: Record "Inventory Setup";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        InTransitLocation: Record Location;
+    begin
+        // [SCENARIO] When releasing a Transfer Order for an item with variants but "Variant Mandatory if Exists" disabled,
+        // the system should release successfully even without Variant Code.
+
+        // [GIVEN] Initialize test
+        Initialize();
+
+        // [GIVEN] Inventory Setup with "Variant Mandatory if Exists" disabled
+        InventorySetup.Get();
+        InventorySetup.Validate("Variant Mandatory if Exists", false);
+        InventorySetup.Modify(true);
+
+        // [GIVEN] An item with variants available (but not mandatory)
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateVariant(ItemVariant, Item);
+
+        // [GIVEN] Locations for Transfer Order
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationFrom);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] A Transfer Order with a line without Variant Code specified
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandDecInRange(1, 10, 2));
+
+        // [WHEN] Release the Transfer Order
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] Transfer Order is released successfully without Variant Code
+        TransferHeader.Get(TransferHeader."No.");
+        Assert.AreEqual(TransferHeader.Status::Released, TransferHeader.Status, 'Transfer Order should be released.');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Transfer Order Variant Mand.");
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Transfer Order Variant Mand.");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateInventoryPostingSetup();
+
+        LibrarySetupStorage.Save(DATABASE::"Inventory Setup");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Transfer Order Variant Mand.");
+    end;
+}

