+codeunit 137083 "SCM Consumption Multiple Lot ILE"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Consumption] [Item Tracking] [Reservation]
+        IsInitialized := false;
+    end;
+
+    var
+        LocationBlue: Record Location;
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ConsumptionItemJournalTemplate: Record "Item Journal Template";
+        ConsumptionItemJournalBatch: Record "Item Journal Batch";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostConsumptionReservedToMultipleLotTrackedILEs()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ProductionOrder: Record "Production Order";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ItemTrackingCode: Record "Item Tracking Code";
+        LotNo: Code[50];
+        TotalQty: Decimal;
+        Qty1: Decimal;
+        Qty2: Decimal;
+        Qty3: Decimal;
+    begin
+        // [FEATURE] [Consumption] [Item Tracking] [Reservation]
+        // [SCENARIO] Post consumption that is reserved to multiple Lot Tracked ILEs with the same Lot number
+        // This test verifies the fix for the "You have insufficient quantity of Item xxx on Inventory" error
+        // that occurred when posting consumption reserved to multiple Lot Tracked ILEs.
+
+        // [GIVEN] Initialize test data
+        Initialize();
+
+        // [GIVEN] Create a Lot-tracked component item with Reserve = Always
+        Qty1 := 5;
+        Qty2 := 10;
+        Qty3 := 20;
+        TotalQty := Qty1 + Qty2 + Qty3; // 35
+
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        ItemTrackingCode.Validate("Lot Warehouse Tracking", true);
+        ItemTrackingCode.Modify(true);
+
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        ComponentItem.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        ComponentItem.Validate(Reserve, ComponentItem.Reserve::Always);
+        ComponentItem.Validate("Flushing Method", ComponentItem."Flushing Method"::Manual);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Create parent (produced) item with Production BOM using the component
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        CreateProductionBOMLineWithQtyPer(ProductionBOMHeader, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create 3 Item Journal lines with the same Lot Number for the component (5, 10, 20 qty = 35 total)
+        LotNo := LibraryUtility.GenerateGUID();
+        CreateAndPostItemJnlLineWithLotTracking(ComponentItem."No.", Qty1, LocationBlue.Code, LotNo);
+        CreateAndPostItemJnlLineWithLotTracking(ComponentItem."No.", Qty2, LocationBlue.Code, LotNo);
+        CreateAndPostItemJnlLineWithLotTracking(ComponentItem."No.", Qty3, LocationBlue.Code, LotNo);
+
+        // [GIVEN] Verify we have 3 ILEs with the same lot number
+        ItemLedgerEntry.SetRange("Item No.", ComponentItem."No.");
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        Assert.AreEqual(3, ItemLedgerEntry.Count(), 'Expected 3 Item Ledger Entries with the same Lot No.');
+
+        // [GIVEN] Create Released Production Order for 35 qty of the parent item at the location
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, ParentItem."No.", TotalQty);
+        ProductionOrder.Validate("Location Code", LocationBlue.Code);
+        ProductionOrder.Modify(true);
+
+        // [GIVEN] Refresh Production Order (this auto-reserves the component because Reserve = Always)
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Verify that the component is reserved to the 3 ILEs
+        VerifyComponentReservedQty(ProductionOrder."No.", ComponentItem."No.", TotalQty);
+
+        // [WHEN] Create and post Consumption Journal for total quantity with the same Lot Number
+        CreateAndPostConsumptionJournalWithLotTracking(ProductionOrder."No.", ComponentItem."No.", LotNo, TotalQty, LocationBlue.Code);
+
+        // [THEN] Consumption is posted successfully - verify consumption Item Ledger Entry exists
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", ComponentItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        ItemLedgerEntry.CalcSums(Quantity);
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Consumption quantity should be negative total qty');
+
+        // [THEN] Verify remaining quantity of original ILEs is now 0
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", ComponentItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        ItemLedgerEntry.CalcSums("Remaining Quantity");
+        Assert.AreEqual(0, ItemLedgerEntry."Remaining Quantity", 'Remaining quantity should be 0 after consumption');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Consumption Multiple Lot ILE");
+        LibrarySetupStorage.Restore();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Consumption Multiple Lot ILE");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+        NoSeriesSetup();
+        ItemJournalSetup();
+        ConsumptionJournalSetup();
+        CreateLocationWithInventoryPostingSetup(LocationBlue);
+
+        WarehouseEmployee.DeleteAll(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationBlue.Code, true);
+
+        IsInitialized := true;
+        Commit();
+
+        LibrarySetupStorage.Save(Database::"Manufacturing Setup");
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Consumption Multiple Lot ILE");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesSetup.Get();
+        SalesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesSetup.Modify(true);
+
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        LibraryInventory.ItemJournalSetup(ItemJournalTemplate, ItemJournalBatch);
+    end;
+
+    local procedure ConsumptionJournalSetup()
+    begin
+        LibraryInventory.ConsumptionJournalSetup(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+    end;
+
+    local procedure CreateLocationWithInventoryPostingSetup(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+    end;
+
+    local procedure CreateProductionBOMLineWithQtyPer(var ProductionBOMHeader: Record "Production BOM Header"; ItemNo: Code[20]; QtyPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ItemNo, QtyPer);
+    end;
+
+    local procedure CreateAndPostItemJnlLineWithLotTracking(ItemNo: Code[20]; Qty: Decimal; LocationCode: Code[10]; LotNo: Code[50])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Qty);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+
+        LibraryItemTracking.CreateItemJournalLineItemTracking(
+            ReservationEntry, ItemJournalLine, '', LotNo, ItemJournalLine."Quantity (Base)");
+
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndPostConsumptionJournalWithLotTracking(ProductionOrderNo: Code[20]; ItemNo: Code[20]; LotNo: Code[50]; Qty: Decimal; LocationCode: Code[10])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+        ProdOrderLine: Record "Prod. Order Line";
+    begin
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderLine.SetRange(Status, ProdOrderLine.Status::Released);
+        ProdOrderLine.FindFirst();
+
+        LibraryInventory.ClearItemJournal(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Consumption, ItemNo, Qty);
+        ItemJournalLine.Validate("Order Type", ItemJournalLine."Order Type"::Production);
+        ItemJournalLine.Validate("Order No.", ProductionOrderNo);
+        ItemJournalLine.Validate("Order Line No.", ProdOrderLine."Line No.");
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+
+        LibraryItemTracking.CreateItemJournalLineItemTracking(
+            ReservationEntry, ItemJournalLine, '', LotNo, ItemJournalLine."Quantity (Base)");
+
+        LibraryInventory.PostItemJournalLine(ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name);
+    end;
+
+    local procedure VerifyComponentReservedQty(ProductionOrderNo: Code[20]; ItemNo: Code[20]; ExpectedQty: Decimal)
+    var
+        ProdOrderComponent: Record "Prod. Order Component";
+    begin
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderComponent.SetRange("Item No.", ItemNo);
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.CalcFields("Reserved Quantity");
+        Assert.AreEqual(ExpectedQty, ProdOrderComponent."Reserved Quantity",
+            'Expected component to be fully reserved');
+    end;
+}

diff --git a/src/Apps/W1/Subscription Billing/Test/Customer Contracts/ContractLineChangeItemTest.Codeunit.al b/src/Apps/W1/Subscription Billing/Test/Customer Contracts/ContractLineChangeItemTest.Codeunit.al
new file mode 100644
index 0000000..b957d4f
--- /dev/null
+++ b/src/Apps/W1/Subscription Billing/Test/Customer Contracts/ContractLineChangeItemTest.Codeunit.al	
@@ -0,0 +1,149 @@
+namespace Microsoft.SubscriptionBilling;
+
+using Microsoft.Inventory.Item;
+
+codeunit 148161 "Contract Line Change Item Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    Access = Internal;
+
+    var
+        Assert: Codeunit Assert;
+        ContractTestLibrary: Codeunit "Contract Test Library";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure ChangeItemNoOnContractLineRemovesOriginalSubscriptionLine()
+    var
+        CustomerContract: Record "Customer Subscription Contract";
+        CustomerContractLine: Record "Cust. Sub. Contract Line";
+        SubscriptionLine: Record "Subscription Line";
+        Item1: Record Item;
+        Item2: Record Item;
+        OriginalSubscriptionLineEntryNo: Integer;
+    begin
+        // [SCENARIO] When the item No. is changed in a manually created contract line, the original subscription line
+        // (created in the contract line) should be deleted, and a new subscription line for the new item should be created.
+        // This prevents the original item from being invoiced when it's no longer part of the contract.
+
+        // [GIVEN] Initialize the test environment
+        Initialize();
+
+        // [GIVEN] Create two items with Subscription Option = "Sales with Service Commitment", no subscription package assigned
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item1, Enum::"Item Service Commitment Type"::"Sales with Service Commitment");
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item2, Enum::"Item Service Commitment Type"::"Sales with Service Commitment");
+
+        // [GIVEN] Create a Customer Contract with a manual contract line for Item1
+        CreateCustomerContractWithManualContractLine(CustomerContract, CustomerContractLine, Item1);
+
+        // [GIVEN] Store the original subscription line entry no. before changing the item
+        OriginalSubscriptionLineEntryNo := CustomerContractLine."Subscription Line Entry No.";
+        Assert.AreNotEqual(0, OriginalSubscriptionLineEntryNo, 'Subscription Line Entry No. should be set after contract line creation.');
+
+        // [GIVEN] Verify the subscription line is connected to the contract before change
+        SubscriptionLine.Get(OriginalSubscriptionLineEntryNo);
+        Assert.AreEqual(CustomerContract."No.", SubscriptionLine."Subscription Contract No.",
+            'Subscription Line should be connected to the contract before changing item.');
+
+        // [WHEN] Change the item No. on the contract line to a different item
+        CustomerContractLine.Validate("No.", Item2."No.");
+        CustomerContractLine.Modify(true);
+
+        // [THEN] The original subscription line should be deleted (since it was created in the contract line)
+        Assert.IsFalse(SubscriptionLine.Get(OriginalSubscriptionLineEntryNo),
+            'Original Subscription Line created in contract line should be deleted after changing item.');
+
+        // [THEN] A new subscription line should be created and linked to the contract
+        Assert.AreNotEqual(OriginalSubscriptionLineEntryNo, CustomerContractLine."Subscription Line Entry No.",
+            'A new Subscription Line should be created after changing item.');
+        SubscriptionLine.Get(CustomerContractLine."Subscription Line Entry No.");
+        Assert.AreEqual(CustomerContract."No.", SubscriptionLine."Subscription Contract No.",
+            'New Subscription Line should be connected to the contract.');
+    end;
+
+    [Test]
+    procedure ChangeItemNoOnContractLineEnsuresOnlyNewItemInContract()
+    var
+        CustomerContract: Record "Customer Subscription Contract";
+        CustomerContractLine: Record "Cust. Sub. Contract Line";
+        SubscriptionLine: Record "Subscription Line";
+        Item1: Record Item;
+        Item2: Record Item;
+        OriginalSubscriptionLineEntryNo: Integer;
+    begin
+        // [SCENARIO] When the item No. is changed in a manually created contract line, only the new item should be
+        // linked to the contract for invoicing. The original item's subscription line should be removed to prevent
+        // it from being invoiced incorrectly.
+
+        // [GIVEN] Initialize the test environment
+        Initialize();
+
+        // [GIVEN] Create two items with Subscription Option = "Sales with Service Commitment"
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item1, Enum::"Item Service Commitment Type"::"Sales with Service Commitment");
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item2, Enum::"Item Service Commitment Type"::"Sales with Service Commitment");
+
+        // [GIVEN] Create a Customer Contract with a manual contract line for Item1
+        CreateCustomerContractWithManualContractLine(CustomerContract, CustomerContractLine, Item1);
+        OriginalSubscriptionLineEntryNo := CustomerContractLine."Subscription Line Entry No.";
+
+        // [WHEN] Change the item No. on the contract line to Item2
+        CustomerContractLine.Validate("No.", Item2."No.");
+        CustomerContractLine.Modify(true);
+
+        // [THEN] The original subscription line should no longer exist (since it was created in contract line)
+        Assert.IsFalse(SubscriptionLine.Get(OriginalSubscriptionLineEntryNo),
+            'Original Subscription Line should be removed after changing item.');
+
+        // [THEN] Only one subscription line should be linked to the contract - for the new item
+        SubscriptionLine.Reset();
+        SubscriptionLine.SetRange("Subscription Contract No.", CustomerContract."No.");
+        Assert.AreEqual(1, SubscriptionLine.Count(),
+            'Only one Subscription Line should be connected to the contract after item change.');
+
+        // [THEN] Verify it's linked to the new item via the contract line
+        CustomerContractLine.Find();
+        SubscriptionLine.Get(CustomerContractLine."Subscription Line Entry No.");
+        Assert.AreEqual(Item2."No.", CustomerContractLine."No.",
+            'Contract line should be for the new item.');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Contract Line Change Item Test");
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Contract Line Change Item Test");
+
+        ContractTestLibrary.DeleteAllContractRecords();
+
+        if IsInitialized then
+            exit;
+
+        ContractTestLibrary.InitContractsApp();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Contract Line Change Item Test");
+
+        IsInitialized := true;
+    end;
+
+    local procedure CreateCustomerContractWithManualContractLine(var CustomerContract: Record "Customer Subscription Contract"; var CustomerContractLine: Record "Cust. Sub. Contract Line"; Item: Record Item)
+    var
+        Customer: Record Customer;
+    begin
+        // Create a customer
+        ContractTestLibrary.CreateCustomer(Customer);
+
+        // Create the customer contract
+        ContractTestLibrary.CreateCustomerContract(CustomerContract, Customer."No.");
+
+        // Manually create a contract line for the item (simulating manual entry)
+        CustomerContractLine.Init();
+        CustomerContractLine."Subscription Contract No." := CustomerContract."No.";
+        CustomerContractLine."Line No." := CustomerContractLine.GetNextLineNo(CustomerContract."No.");
+        CustomerContractLine.Validate("Contract Line Type", Enum::"Contract Line Type"::Item);
+        CustomerContractLine.Insert(true);
+
+        // Set the item No. which creates the subscription and subscription line
+        CustomerContractLine.Validate("No.", Item."No.");
+        CustomerContractLine.Modify(true);
+    end;
+}

