             'Total Cost (LCY) with Non-Deductible VAT amount is not correct in Job Journal Line');
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure JobJnlLineWithNonDeductNormalVATFromGenJnlLineWithFCYJob()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJnlLine: Record "Gen. Journal Line";
+        JobJnlLine: Record "Job Journal Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        Customer: Record Customer;
+        JobTransferLine: Codeunit "Job Transfer Line";
+        CurrencyCode: Code[10];
+        DeductiblePercent: Decimal;
+        ExpectedNonDedVATAmountLCY: Decimal;
+    begin
+        // [FEATURE] [Normal VAT] [UT] [Currency]
+        // [SCENARIO 564XXX] Job journal line built from the general journal line includes non deductible VAT in "Unit Cost"
+        // when the job has a foreign currency and the general journal line is in LCY
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup, where "Tax Calculation Type"::"Normal VAT", 'Deductible %' is '60'
+        DeductiblePercent := LibraryRandom.RandInt(90);
+        CreateNonDeductibleVATPostingSetup(VATPostingSetup, "Tax Calculation Type"::"Normal VAT", '', DeductiblePercent);
+
+        // [GIVEN] Currency code EUR with exchange rate = 10
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 10, 10);
+
+        // [GIVEN] A Job with currency code EUR
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", CurrencyCode);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General journal line in LCY where line contains Amount = 100, "Job No." = 'J', "Job Task No." = 'JT', "Job Line Type" = 'Billable'
+        LibraryJob.CreateJobGLJournalLine(GenJnlLine."Job Line Type"::Billable, JobTask, GenJnlLine);
+        GenJnlLine.Validate("Gen. Posting Type", GenJnlLine."Gen. Posting Type"::Purchase);
+        GenJnlLine.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GenJnlLine.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GenJnlLine.Modify(true);
+
+        // [GIVEN] Calculate expected Non-Deductible VAT Amount in LCY considering the currency conversion
+        // When Gen. Journal Line is in LCY (Currency Factor = 0) and Job has FCY (Job Currency Factor <> 0)
+        // The Non-Deductible VAT Amount should be converted using the Job Currency Factor from GetGenJnlLineToJobCurrencyFactor()
+        ExpectedNonDedVATAmountLCY := Round(GenJnlLine."Non-Deductible VAT Amount" * GenJnlLine.GetGenJnlLineToJobCurrencyFactor());
+
+        // [WHEN] Run FromGenJnlLineToJnlLine
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
+
+        // [THEN] JobJnlLine contains "Unit Cost (LCY)" including the correctly converted Non-Deductible VAT amount
+        Assert.AreEqual(
+            Round(JobJnlLine."Unit Cost (LCY)"),
+            Round((GenJnlLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY) / GenJnlLine."Job Quantity"),
+            'Unit Cost (LCY) with Non-Deductible VAT amount is not correctly converted for FCY Job');
+
+        // [THEN] JobJnlLine contains "Total Cost (LCY)" including the correctly converted Non-Deductible VAT amount
+        Assert.AreEqual(
+            Round(JobJnlLine."Total Cost (LCY)"),
+            Round(GenJnlLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY),
+            'Total Cost (LCY) with Non-Deductible VAT amount is not correctly converted for FCY Job');
+    end;
+
