+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionLineCopy: Record "Requisition Line";
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        CarryOutActionMsgPlan: Report "Carry Out Action Msg. - Plan.";
+        Quantity: Decimal;
+        PurchaseOrderDate: Date;
+        SalesShipmentDate: Date;
+    begin
+        // [FEATURE] [Carry Out Action Message] [Action Message Filter]
+        // [SCENARIO] When filtering Planning Worksheet by Action Message and running Carry Out Action Message,
+        // only lines matching the filter should be processed.
+        // Bug: Prior to fix, filtering by Action Message "Cancel" would also process "New" lines.
+
+        // [GIVEN] An item with Reordering Policy = Order and Replenishment System = Purchase
+        Initialize();
+        CreateOrderItem(Item);
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        PurchaseOrderDate := WorkDate();
+        SalesShipmentDate := CalcDate('<+10D>', WorkDate());
+
+        // [GIVEN] A purchase order for the item dated at WorkDate
+        CreatePurchaseOrder(PurchaseHeader, PurchaseLine, Item."No.", Quantity, PurchaseOrderDate);
+
+        // [GIVEN] A sales order for the item with shipment date in the future
+        // This will cause planning to suggest Cancel for the existing PO (no demand at WorkDate)
+        // and New for the sales order demand at future date
+        CreateSalesOrderWithShipmentDate(SalesHeader, SalesLine, Item."No.", Quantity, SalesShipmentDate);
+
+        // [GIVEN] Calculate Regenerative Plan for the item
+        SelectRequisitionTemplate(ReqWkshTemplate, ReqWkshTemplate.Type::Planning);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), CalcDate('<+30D>', WorkDate()));
+
+        // [GIVEN] Two planning lines exist: one with Action Message = Cancel and one with Action Message = New
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected a planning line with Action Message = Cancel');
+
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected a planning line with Action Message = New');
+
+        // [GIVEN] Accept Action Message is set on all lines
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.FindSet();
+        repeat
+            RequisitionLine.Validate("Accept Action Message", true);
+            RequisitionLine.Modify(true);
+        until RequisitionLine.Next() = 0;
+
+        // [WHEN] Filter the planning lines by Action Message = Cancel and run Carry Out Action Message
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+
+        Commit();
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0); // Make Purchase Orders only
+        CarryOutActionMsgPlan.SetHideDialog(true);
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The planning line with Action Message = Cancel should be processed (deleted)
+        FilterOnRequisitionLine(RequisitionLineCopy, Item."No.");
+        RequisitionLineCopy.SetRange("Action Message", RequisitionLineCopy."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLineCopy.IsEmpty(), 'Planning line with Action Message = Cancel should have been processed and deleted');
+
+        // [THEN] The planning line with Action Message = New should NOT be processed (still exists)
+        FilterOnRequisitionLine(RequisitionLineCopy, Item."No.");
+        RequisitionLineCopy.SetRange("Action Message", RequisitionLineCopy."Action Message"::New);
+        Assert.IsFalse(RequisitionLineCopy.IsEmpty(), 'Planning line with Action Message = New should NOT have been processed when filtering by Cancel');
+
+        // [THEN] The original purchase order should be deleted (Cancel action was carried out)
+        PurchaseHeader.SetRange("Document Type", PurchaseHeader."Document Type"::Order);
+        PurchaseHeader.SetRange("No.", PurchaseHeader."No.");
+        Assert.IsTrue(PurchaseHeader.IsEmpty() or not PurchaseHeader.Get(PurchaseHeader."Document Type"::Order, PurchaseHeader."No."),
+            'Original purchase order should have been canceled');
+
+        // [THEN] No new purchase order should have been created for the "New" line
+        // (since that line was filtered out and should not have been processed)
+        PurchaseLine.Reset();
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", Item."No.");
+        PurchaseLine.SetRange("Expected Receipt Date", SalesShipmentDate);
+        Assert.IsTrue(PurchaseLine.IsEmpty(), 'No new purchase order should have been created for the New line when filtering by Cancel');
+    end;
+
+    local procedure Initialize()
+    var
+        RequisitionLine: Record "Requisition Line";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+        RequisitionLine.DeleteAll();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+        ItemJournalSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Shipment Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        ItemJournalTemplate.Init();
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        ItemJournalTemplate.Validate("No. Series", LibraryUtility.GetGlobalNoSeriesCode());
+        ItemJournalTemplate.Modify(true);
+
+        ItemJournalBatch.Init();
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        ItemJournalBatch.Modify(true);
+    end;
+
+    local procedure CreateOrderItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::Order);
+        Item.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        Item.Modify(true);
+    end;
+
+    local procedure CreatePurchaseOrder(var PurchaseHeader: Record "Purchase Header"; var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20]; Quantity: Decimal; OrderDate: Date)
+    var
+        Item: Record Item;
+    begin
+        Item.Get(ItemNo);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Item."Vendor No.");
+        PurchaseHeader.Validate("Order Date", OrderDate);
+        PurchaseHeader.Modify(true);
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, ItemNo, Quantity);
+        PurchaseLine.Validate("Expected Receipt Date", OrderDate);
+        PurchaseLine.Modify(true);
+    end;
+
+    local procedure CreateSalesOrderWithShipmentDate(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; Quantity: Decimal; ShipmentDate: Date)
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        SalesHeader.Validate("Shipment Date", ShipmentDate);
+        SalesHeader.Modify(true);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, Quantity);
+        SalesLine.Validate("Shipment Date", ShipmentDate);
+        SalesLine.Modify(true);
+    end;
+
+    local procedure SelectRequisitionTemplate(var ReqWkshTemplate: Record "Req. Wksh. Template"; Type: Enum "Req. Worksheet Template Type")
+    begin
+        ReqWkshTemplate.SetRange(Type, Type);
+        ReqWkshTemplate.SetRange(Recurring, false);
+        ReqWkshTemplate.FindFirst();
+    end;
+
+    local procedure FilterOnRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ItemNo);
+    end;
+}

