diff --git a/test/SCMReservationWorksheetNeverReserve.Codeunit.al b/test/SCMReservationWorksheetNeverReserve.Codeunit.al
new file mode 100644
index 00000000..993924f9
--- /dev/null
+++ b/test/SCMReservationWorksheetNeverReserve.Codeunit.al
@@ -0,0 +1,181 @@
+codeunit 134270 "SCM ResWksh. Never Reserve"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [SCM] [Reservation Worksheet] [Reserve Never]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        DefaultBatchTok: Label 'DEFAULT';
+
+    [Test]
+    [HandlerFunctions('GetDemandToReserveRequestPageHandler')]
+    procedure GetDemandExcludesItemWithReserveNeverOnSalesOrder()
+    var
+        Item: Record Item;
+        ItemNeverReserve: Record Item;
+        Location: Record Location;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesHeaderNeverReserve: Record "Sales Header";
+        SalesLineNeverReserve: Record "Sales Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationWkshBatch: Record "Reservation Wksh. Batch";
+        ReservationWkshLine: Record "Reservation Wksh. Line";
+        ReservationWorksheetMgt: Codeunit "Reservation Worksheet Mgt.";
+        ItemNoFilter: Text;
+    begin
+        // [SCENARIO] Get Demand to Reserve should NOT pull in demand for items with Reserve = Never
+        // Bug: Reservation Worksheet creates Reservations for Items that have 'Reserve' = Never
+        Initialize();
+
+        // [GIVEN] A location with inventory posting setup
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // [GIVEN] Item "A" with Reserve = Optional (default)
+        LibraryInventory.CreateItem(Item);
+        Item.TestField(Reserve, Item.Reserve::Optional);
+
+        // [GIVEN] Item "B" with Reserve = Never
+        LibraryInventory.CreateItem(ItemNeverReserve);
+        ItemNeverReserve.Validate(Reserve, ItemNeverReserve.Reserve::Never);
+        ItemNeverReserve.Modify(true);
+
+        // [GIVEN] Post inventory for both items (10 qty each)
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", Location.Code, '', 10);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNeverReserve."No.", Location.Code, '', 10);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Sales Order for Item "A" (Reserve = Optional) with 3 qty
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', Item."No.", 3, Location.Code, WorkDate() + 5);
+
+        // [GIVEN] Sales Order for Item "B" (Reserve = Never) with 3 qty
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeaderNeverReserve, SalesLineNeverReserve, SalesHeaderNeverReserve."Document Type"::Order, '',
+            ItemNeverReserve."No.", 3, Location.Code, WorkDate() + 5);
+
+        // Verify that Reserve = Never was inherited from Item to Sales Line
+        SalesLineNeverReserve.TestField(Reserve, SalesLineNeverReserve.Reserve::Never);
+
+        // [WHEN] Run "Get Demand" filtered by both items in a default reservation worksheet batch
+        ReservationWkshBatch.FindFirst();
+        ItemNoFilter := Item."No." + '|' + ItemNeverReserve."No.";
+        Commit();
+        LibraryVariableStorage.Enqueue(ItemNoFilter);
+        ReservationWorksheetMgt.CalculateDemand(ReservationWkshBatch.Name);
+
+        // [THEN] Reservation Worksheet Line exists for Item "A" (Reserve = Optional)
+        ReservationWkshLine.SetRange("Journal Batch Name", ReservationWkshBatch.Name);
+        ReservationWkshLine.SetRange("Item No.", Item."No.");
+        Assert.RecordIsNotEmpty(ReservationWkshLine);
+
+        // [THEN] Reservation Worksheet Line does NOT exist for Item "B" (Reserve = Never)
+        ReservationWkshLine.SetRange("Item No.", ItemNeverReserve."No.");
+        Assert.RecordIsEmpty(ReservationWkshLine);
+    end;
+
+    [Test]
+    [HandlerFunctions('GetDemandToReserveRequestPageHandler')]
+    procedure GetDemandExcludesSalesLineWithReserveNeverWhenItemIsOptional()
+    var
+        Item: Record Item;
+        Location: Record Location;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesHeaderNeverReserve: Record "Sales Header";
+        SalesLineNeverReserve: Record "Sales Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationWkshBatch: Record "Reservation Wksh. Batch";
+        ReservationWkshLine: Record "Reservation Wksh. Line";
+        ReservationWorksheetMgt: Codeunit "Reservation Worksheet Mgt.";
+    begin
+        // [SCENARIO] Get Demand should exclude Sales Lines where Reserve = Never, even if item has Reserve = Optional
+        Initialize();
+
+        // [GIVEN] A location with inventory posting setup
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+
+        // [GIVEN] Item with Reserve = Optional (default)
+        LibraryInventory.CreateItem(Item);
+        Item.TestField(Reserve, Item.Reserve::Optional);
+
+        // [GIVEN] Post inventory for the item (20 qty)
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", Location.Code, '', 20);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Sales Order 1 with Reserve = Optional (inherited from Item)
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', Item."No.", 3, Location.Code, WorkDate() + 5);
+        SalesLine.TestField(Reserve, SalesLine.Reserve::Optional);
+
+        // [GIVEN] Sales Order 2 with Reserve = Never (manually set on line)
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeaderNeverReserve, SalesLineNeverReserve, SalesHeaderNeverReserve."Document Type"::Order, '',
+            Item."No.", 3, Location.Code, WorkDate() + 10);
+        SalesLineNeverReserve.Validate(Reserve, SalesLineNeverReserve.Reserve::Never);
+        SalesLineNeverReserve.Modify(true);
+
+        // [WHEN] Run "Get Demand" filtered by the item
+        ReservationWkshBatch.FindFirst();
+        Commit();
+        LibraryVariableStorage.Enqueue(Item."No.");
+        ReservationWorksheetMgt.CalculateDemand(ReservationWkshBatch.Name);
+
+        // [THEN] Reservation Worksheet Line exists for Sales Order 1 (Reserve = Optional)
+        ReservationWkshLine.SetRange("Journal Batch Name", ReservationWkshBatch.Name);
+        ReservationWkshLine.SetRange("Source ID", SalesHeader."No.");
+        Assert.RecordIsNotEmpty(ReservationWkshLine);
+
+        // [THEN] Reservation Worksheet Line does NOT exist for Sales Order 2 (Reserve = Never)
+        ReservationWkshLine.SetRange("Source ID", SalesHeaderNeverReserve."No.");
+        Assert.RecordIsEmpty(ReservationWkshLine);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM ResWksh. Never Reserve");
+        LibraryVariableStorage.Clear();
+
+        ClearReservationWorksheets();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM ResWksh. Never Reserve");
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM ResWksh. Never Reserve");
+    end;
+
+    local procedure ClearReservationWorksheets()
+    var
+        ReservationWkshBatch: Record "Reservation Wksh. Batch";
+    begin
+        ReservationWkshBatch.DeleteAll(true);
+
+        ReservationWkshBatch.Init();
+        ReservationWkshBatch.Name := DefaultBatchTok;
+        ReservationWkshBatch.Insert();
+    end;
+
+    [RequestPageHandler]
+    procedure GetDemandToReserveRequestPageHandler(var GetDemandToReserve: TestRequestPage "Get Demand To Reserve")
+    begin
+        GetDemandToReserve.FilterItem.SetFilter("No.", LibraryVariableStorage.DequeueText());
+        GetDemandToReserve.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdWhseHandling.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdWhseHandling.Codeunit.al
