diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMReplanProdOrderInputQty.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMReplanProdOrderInputQty.Codeunit.al
