--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMReplanProdOrderInputQty.Codeunit.al
@@ -0,0 +1,203 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.Routing;
+using Microsoft.Manufacturing.ProductionBOM;
+using Microsoft.Manufacturing.WorkCenter;
+using Microsoft.Manufacturing.Journal;
+using Microsoft.Inventory.Journal;
+using System.TestLibraries.Utilities;
+
+codeunit 137099 "SCM Replan Prod Order InputQty"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        IsInitialized: Boolean;
+        Direction: Option Forward,Backward;
+        CalcMethod: Option "No Levels","One level","All levels";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReplanReleasedProdOrderRecalculatesInputQtyAfterPartialOutput()
+    var
+        Item: Record Item;
+        ChildItem: Record Item;
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+        InitialQuantity: Decimal;
+        OutputQuantity: Decimal;
+        ExpectedInputQty: Decimal;
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [Replan]
+        // [SCENARIO 101005] When Replan Production Order is run after partial output has been posted,
+        // the Input Quantity on the Prod. Order Routing Line should be recalculated based on remaining quantity.
+        Initialize();
+
+        // [GIVEN] A parent item with a child item in Production BOM, and a routing
+        CreateItemsSetup(Item, ChildItem);
+        CreateRoutingAndUpdateItem(Item);
+
+        // [GIVEN] A Released Production Order for the parent item with quantity = 50
+        InitialQuantity := 50;
+        CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, Item."No.", InitialQuantity, '', '');
+
+        // [GIVEN] Partial output of 20 has been posted via Output Journal
+        OutputQuantity := 20;
+        FindProductionOrderLine(ProdOrderLine, Item."No.");
+        CreateAndPostOutputJournal(ProdOrderLine, OutputQuantity);
+
+        // [WHEN] Replan Production Order with Direction = Backward and CalcMethod = "No Levels"
+        LibraryManufacturing.RunReplanProductionOrder(ProductionOrder, Direction::Backward, CalcMethod::"No Levels");
+
+        // [THEN] The Input Quantity on the Prod. Order Routing Line equals the remaining quantity (50 - 20 = 30)
+        ExpectedInputQty := InitialQuantity - OutputQuantity;
+        FindProductionOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        Assert.AreEqual(
+            ExpectedInputQty,
+            ProdOrderRoutingLine."Input Quantity",
+            'Input Quantity should be recalculated to remaining quantity after Replan');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Replan Prod Order InputQty");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Replan Prod Order InputQty");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Replan Prod Order InputQty");
+    end;
+
+    local procedure CreateItemsSetup(var Item: Record Item; var ChildItem: Record Item)
+    var
+        ProductionBOMHeader: Record "Production BOM Header";
+    begin
+        // Create Child Item
+        LibraryInventory.CreateItem(ChildItem);
+
+        // Create Production BOM, Parent Item and attach Production BOM
+        CreateCertifiedProductionBOM(ProductionBOMHeader, ChildItem);
+        CreateProductionItem(Item, ProductionBOMHeader."No.");
+    end;
+
+    local procedure CreateCertifiedProductionBOM(var ProductionBOMHeader: Record "Production BOM Header"; Item: Record Item)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, Item."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+    end;
+
+    local procedure CreateProductionItem(var Item: Record Item; ProductionBOMNo: Code[20])
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Production BOM No.", ProductionBOMNo);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateRoutingAndUpdateItem(var Item: Record Item)
+    var
+        WorkCenter: Record "Work Center";
+        RoutingHeader: Record "Routing Header";
+        RoutingLine: Record "Routing Line";
+    begin
+        // Create Work Center with Calendar
+        LibraryManufacturing.CreateWorkCenterWithCalendar(WorkCenter);
+
+        // Create Routing
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        LibraryManufacturing.CreateRoutingLine(
+            RoutingHeader, RoutingLine, '', '10', RoutingLine.Type::"Work Center", WorkCenter."No.");
+        RoutingLine.Validate("Setup Time", 10);
+        RoutingLine.Validate("Run Time", 10);
+        RoutingLine.Modify(true);
+        RoutingHeader.Validate(Status, RoutingHeader.Status::Certified);
+        RoutingHeader.Modify(true);
+
+        // Update Routing No on Item
+        Item.Validate("Routing No.", RoutingHeader."No.");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndRefreshProductionOrder(var ProductionOrder: Record "Production Order"; Status: Enum "Production Order Status"; SourceNo: Code[20]; Quantity: Decimal; LocationCode: Code[10]; BinCode: Code[20])
+    begin
+        LibraryManufacturing.CreateProductionOrder(ProductionOrder, Status, ProductionOrder."Source Type"::Item, SourceNo, Quantity);
+        ProductionOrder.Validate("Location Code", LocationCode);
+        ProductionOrder.Validate("Bin Code", BinCode);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+    end;
+
+    local procedure CreateAndPostOutputJournal(ProdOrderLine: Record "Prod. Order Line"; OutputQty: Decimal)
+    var
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+    begin
+        LibraryInventory.CreateItemJournalBatchByType(ItemJournalBatch, ItemJournalBatch."Template Type"::Output);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch, ProdOrderLine."Item No.", ProdOrderLine."Location Code",
+            ProdOrderLine."Variant Code", WorkDate(), ItemJournalLine."Entry Type"::"Positive Adjmt.", 0, 0);
+
+        ItemJournalLine.Validate("Entry Type", ItemJournalLine."Entry Type"::Output);
+        ItemJournalLine.Validate("Order Type", ItemJournalLine."Order Type"::Production);
+        ItemJournalLine.Validate("Order No.", ProdOrderLine."Prod. Order No.");
+        ItemJournalLine.Validate("Order Line No.", ProdOrderLine."Line No.");
+        ItemJournalLine.Validate("Item No.", ProdOrderLine."Item No.");
+
+        ProdOrderRoutingLine.SetRange(Status, ProdOrderLine.Status);
+        ProdOrderRoutingLine.SetRange("Prod. Order No.", ProdOrderLine."Prod. Order No.");
+        ProdOrderRoutingLine.SetRange("Routing Reference No.", ProdOrderLine."Routing Reference No.");
+        if ProdOrderRoutingLine.FindFirst() then
+            ItemJournalLine.Validate("Operation No.", ProdOrderRoutingLine."Operation No.");
+
+        ItemJournalLine.Validate("Output Quantity", OutputQty);
+        ItemJournalLine.Modify(true);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure FindProductionOrderLine(var ProdOrderLine: Record "Prod. Order Line"; ItemNo: Code[20])
+    begin
+        ProdOrderLine.SetRange("Item No.", ItemNo);
+        ProdOrderLine.FindFirst();
+    end;
+
+    local procedure FindProductionOrderRoutingLine(var ProdOrderRoutingLine: Record "Prod. Order Routing Line"; ProductionOrderNo: Code[20])
+    begin
+        ProdOrderRoutingLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderRoutingLine.FindFirst();
+    end;
+}

