@@ -0,0 +1,188 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Assembly.Test;
+
+using Microsoft.Assembly.Setup;
+using Microsoft.Inventory.Setup;
+using Microsoft.Assembly.Document;
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.BOM;
+using Microsoft.Inventory.Costing;
+using Microsoft.Assembly.Posting;
+using Microsoft.Manufacturing.Setup;
+using Microsoft.Inventory.Journal;
+
+codeunit 137940 "SCM Assembly Non-Inv. Cost"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Assembly] [SCM] [Non-Inventory Cost]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryCosting: Codeunit "Library - Costing";
+        LibraryAssembly: Codeunit "Library - Assembly";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        isInitialized: Boolean;
+
+    [Test]
+    procedure AdjustCostForAssemblyWithNonInventoryComponentDoesNotFailWhenNonInvCostToProdEnabled()
+    var
+        AssemblyItem: Record Item;
+        NonInvItem: Record Item;
+        ComponentItem: Record Item;
+        AssemblyHeader: Record "Assembly Header";
+    begin
+        // [SCENARIO 553982] When "Inc. Non. Inv. Cost To Prod" is enabled in Manufacturing Setup,
+        // running Adjust Cost Item Entries for an Assembly Order with a Non-Inventory component
+        // should not fail with "Direct Cost - Non Inventory is not allowed" error.
+        Initialize();
+
+        // [GIVEN] "Inc. Non. Inv. Cost To Prod" is enabled in Manufacturing Setup.
+        LibraryManufacturing.UpdateNonInventoryCostToProductionInManufacturingSetup(true);
+
+        // [GIVEN] Set Automatic Cost Adjustment to Never to test manual adjustment.
+        LibraryInventory.SetAutomaticCostAdjmtNever();
+
+        // [GIVEN] An Assembly Item with a Non-Inventory item component and a regular Item component.
+        CreateAssemblyItemWithNonInvComponent(AssemblyItem, NonInvItem, ComponentItem);
+
+        // [GIVEN] Inventory exists for the regular item component.
+        CreateAndPostItemJournalLine(ComponentItem."No.", LibraryRandom.RandIntInRange(10, 20));
+
+        // [GIVEN] An Assembly Order is created and posted.
+        CreateAndPostAssemblyOrder(AssemblyHeader, AssemblyItem."No.", LibraryRandom.RandIntInRange(1, 5));
+
+        // [WHEN] Adjust Cost Item Entries is run.
+        LibraryCosting.AdjustCostItemEntries(AssemblyItem."No.", '');
+
+        // [THEN] The cost adjustment completes without error.
+        // Without the fix, this would fail with:
+        // "The following combination Item Ledger Entry Type = Assembly Output, Entry Type = Direct Cost - Non Inventory, and Expected Cost = No is not allowed."
+    end;
+
+    [Test]
+    procedure AdjustCostForAssemblyWithNonInventoryComponentWithAutomaticCostAdjustment()
+    var
+        AssemblyItem: Record Item;
+        NonInvItem: Record Item;
+        ComponentItem: Record Item;
+        AssemblyHeader: Record "Assembly Header";
+    begin
+        // [SCENARIO 553982] When "Inc. Non. Inv. Cost To Prod" is enabled in Manufacturing Setup
+        // and Automatic Cost Adjustment is enabled, posting an Assembly Order with a Non-Inventory
+        // component should not fail.
+        Initialize();
+
+        // [GIVEN] "Inc. Non. Inv. Cost To Prod" is enabled in Manufacturing Setup.
+        LibraryManufacturing.UpdateNonInventoryCostToProductionInManufacturingSetup(true);
+
+        // [GIVEN] Set Automatic Cost Adjustment to Always.
+        LibraryInventory.SetAutomaticCostAdjmtAlways();
+
+        // [GIVEN] An Assembly Item with a Non-Inventory item component and a regular Item component.
+        CreateAssemblyItemWithNonInvComponent(AssemblyItem, NonInvItem, ComponentItem);
+
+        // [GIVEN] Inventory exists for the regular item component.
+        CreateAndPostItemJournalLine(ComponentItem."No.", LibraryRandom.RandIntInRange(10, 20));
+
+        // [WHEN] An Assembly Order is created and posted (automatic cost adjustment will run).
+        CreateAndPostAssemblyOrder(AssemblyHeader, AssemblyItem."No.", LibraryRandom.RandIntInRange(1, 5));
+
+        // [THEN] The posting and automatic cost adjustment complete without error.
+        // Without the fix, this would fail with:
+        // "The following combination Item Ledger Entry Type = Assembly Output, Entry Type = Direct Cost - Non Inventory, and Expected Cost = No is not allowed."
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Assembly Non-Inv. Cost");
+
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Assembly Non-Inv. Cost");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+
+        LibrarySetupStorage.Save(Database::"Inventory Setup");
+        LibrarySetupStorage.Save(Database::"Manufacturing Setup");
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Assembly Non-Inv. Cost");
+    end;
+
+    local procedure CreateAssemblyItemWithNonInvComponent(var AssemblyItem: Record Item; var NonInvItem: Record Item; var ComponentItem: Record Item)
+    var
+        BOMComponent: Record "BOM Component";
+    begin
+        // Create Assembly Item
+        LibraryInventory.CreateItem(AssemblyItem);
+        AssemblyItem.Validate("Replenishment System", AssemblyItem."Replenishment System"::Assembly);
+        AssemblyItem.Modify(true);
+
+        // Create Non-Inventory Item component
+        LibraryInventory.CreateNonInventoryTypeItem(NonInvItem);
+
+        // Create regular Item component
+        LibraryInventory.CreateItem(ComponentItem);
+
+        // Add Non-Inventory item as BOM component
+        LibraryInventory.CreateBOMComponent(
+            BOMComponent,
+            AssemblyItem."No.",
+            BOMComponent.Type::Item,
+            NonInvItem."No.",
+            LibraryRandom.RandIntInRange(1, 5),
+            NonInvItem."Base Unit of Measure");
+
+        // Add regular item as BOM component
+        LibraryInventory.CreateBOMComponent(
+            BOMComponent,
+            AssemblyItem."No.",
+            BOMComponent.Type::Item,
+            ComponentItem."No.",
+            LibraryRandom.RandIntInRange(1, 5),
+            ComponentItem."Base Unit of Measure");
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine,
+            ItemJournalTemplate.Name,
+            ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.",
+            ItemNo,
+            Quantity);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndPostAssemblyOrder(var AssemblyHeader: Record "Assembly Header"; ItemNo: Code[20]; Quantity: Decimal)
+    begin
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader, WorkDate(), ItemNo, '', Quantity, '');
+        LibraryAssembly.PostAssemblyHeader(AssemblyHeader, '');
+    end;
+}

