+codeunit 134829 "Item Rename With Variant Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item] [Item Variant] [Rename]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemWithVariantAndValueEntriesSucceeds()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO 510015] Renaming an Item No. succeeds when the Item has Variants with posted Value Entries
+        // The rename should not fail even though Item Variant rename is cascaded with RunTrigger=false
+        Initialize();
+
+        // [GIVEN] Create an item with a variant
+        LibraryInventory.CreateItem(Item);
+        OldItemNo := Item."No.";
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Post item journal entries to create Value Entries for the item with the variant
+        LibraryInventory.CreateItemJournalBatchByType(ItemJournalBatch, "Item Journal Template Type"::Item);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine,
+            ItemJournalBatch,
