+codeunit 134995 "ERM Purchase Journal Doc Amt"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Document Amount] [Currency]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+        AmountWithThreeDecimalsErr: Label 'Document Amount should accept 3 decimal places. Expected: %1, Actual: %2';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocAmountAcceptsThreeDecimalPlaces()
+    var
+        Currency: Record Currency;
+        PurchaseJournal: TestPage "Purchase Journal";
+        ExpectedAmount: Decimal;
+    begin
+        // [SCENARIO 000001] Document Amount in Purchase Journal should accept 3 decimal places when currency has 3 decimal places
+        // [GIVEN] A currency with 3 decimal places (like TND - Tunisian Dinar)
+        Initialize();
+        CreateCurrencyWithThreeDecimalPlaces(Currency);
+
+        // [WHEN] User opens Purchase Journal and enters an amount with 3 decimal places (1.234)
+        ExpectedAmount := 1.234;
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.New();
+        PurchaseJournal."Currency Code".SetValue(Currency.Code);
+        PurchaseJournal.DocumentAmount.SetValue(ExpectedAmount);
+
+        // [THEN] The Document Amount field should accept the value with 3 decimal places without error
+        Assert.AreEqual(
+            Format(ExpectedAmount),
+            PurchaseJournal.DocumentAmount.Value,
+            StrSubstNo(AmountWithThreeDecimalsErr, Format(ExpectedAmount), PurchaseJournal.DocumentAmount.Value));
+
+        PurchaseJournal.Close();
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocAmountHandlesExactlyThreeDecimals()
+    var
+        Currency: Record Currency;
+        PurchaseJournal: TestPage "Purchase Journal";
+        ExpectedAmount: Decimal;
+    begin
+        // [SCENARIO 000002] Document Amount in Purchase Journal should correctly handle amounts with exactly 3 decimal places
+        // [GIVEN] A currency with 3 decimal places
+        Initialize();
+        CreateCurrencyWithThreeDecimalPlaces(Currency);
+
+        // [WHEN] User enters different amounts with 3 decimal places
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.New();
+        PurchaseJournal."Currency Code".SetValue(Currency.Code);
+
+        // Test with 123.456
+        ExpectedAmount := 123.456;
+        PurchaseJournal.DocumentAmount.SetValue(ExpectedAmount);
+
+        // [THEN] The Amount field should be correctly populated (negative for Invoice)
+        Assert.AreEqual(
+            Format(-ExpectedAmount),
+            PurchaseJournal.Amount.Value,
+            StrSubstNo(AmountWithThreeDecimalsErr, Format(-ExpectedAmount), PurchaseJournal.Amount.Value));
+
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        GenJnlManagement: Codeunit "GenJnlManagement";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"ERM Purchase Journal Doc Amt");
+
+        if isInitialized then
+            exit;
+
+        GenJnlManagement.SetJournalSimplePageModePreference(true, Page::"Purchase Journal");
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"ERM Purchase Journal Doc Amt");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateAccountInVendorPostingGroups();
+        LibraryERMCountryData.RemoveBlankGenJournalTemplate();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"ERM Purchase Journal Doc Amt");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(var Currency: Record Currency)
+    begin
+        // Create a currency similar to TND (Tunisian Dinar) which uses 3 decimal places
+        LibraryERM.CreateCurrency(Currency);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Unit-Amount Decimal Places", '3:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Validate("Unit-Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+
+        // Create exchange rate for the currency
+        LibraryERM.CreateExchangeRate(Currency.Code, WorkDate(), LibraryRandom.RandDec(10, 2), LibraryRandom.RandDec(10, 2));
+    end;
+}

