+namespace Microsoft.Assembly.Test;
+
+using Microsoft.Assembly.Document;
+using Microsoft.Inventory.BOM;
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Journal;
+
+codeunit 137949 "SCM Assembly Avail Warning Due"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Assembly] [Availability Warning] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryAssembly: Codeunit "Library - Assembly";
+        LibraryInventory: Codeunit "Library - Inventory";
+        Initialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Assembly Avail Warning Due");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Assembly Avail Warning Due");
+
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Assembly Avail Warning Due");
+    end;
+
+    [Test]
+    procedure AvailWarningConsidersDueDateNotAllDemand()
+    var
+        AsmItem: Record Item;
+        CompItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        ItemJournalLine: Record "Item Journal Line";
+        AssemblyHeader: array[2] of Record "Assembly Header";
+        AssemblyLine: array[2] of Record "Assembly Line";
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [Availability Warning] [Due Date]
+        // [SCENARIO] Avail. Warning on Assembly Order considers Due Date rather than all demand for the component
+        // Bug Repro: First assembly order should show no warning when inventory covers its due date demand,
+        // even if future assembly orders create additional demand that exceeds total inventory.
+        Initialize();
+
+        // [GIVEN] Assembly item with component. Qty Per = 2 (component per assembled item)
+        QtyPer := 2;
+        LibraryInventory.CreateItem(AsmItem);
+        AsmItem.Validate("Replenishment System", AsmItem."Replenishment System"::Assembly);
+        AsmItem.Modify(true);
+
+        LibraryInventory.CreateItem(CompItem);
+        LibraryInventory.CreateBOMComponent(
+          BOMComponent, AsmItem."No.", BOMComponent.Type::Item, CompItem."No.", QtyPer, CompItem."Base Unit of Measure");
+
+        // [GIVEN] Post 2 pcs of component to inventory (enough for 1 assembly of 1 finished item)
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, CompItem."No.", '', '', 2);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] First assembly order for 1 pc on WorkDate() + 5 (needs 2 components)
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[1], WorkDate() + 5, AsmItem."No.", '', 1, '');
+        FindAssemblyLine(AssemblyLine[1], AssemblyHeader[1], CompItem."No.");
+
+        // [GIVEN] Second assembly order for 3 pc on WorkDate() + 10 (needs 6 components - creates future demand)
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[2], WorkDate() + 10, AsmItem."No.", '', 3, '');
+        FindAssemblyLine(AssemblyLine[2], AssemblyHeader[2], CompItem."No.");
+
+        // [WHEN] Check availability warning on first assembly order line (due date before second order)
+        AssemblyLine[1].UpdateAvailWarning();
+
+        // [THEN] First assembly line should NOT show availability warning (inventory = 2, demand by due date = 2)
+        Assert.IsFalse(
+          AssemblyLine[1]."Avail. Warning",
+          'First assembly order should not show availability warning when inventory covers its due date demand');
+
+        // [WHEN] Check availability warning on second assembly order line
+        AssemblyLine[2].UpdateAvailWarning();
+
+        // [THEN] Second assembly line SHOULD show availability warning (needs 6 more but only 0 remaining after first order)
+        Assert.IsTrue(
+          AssemblyLine[2]."Avail. Warning",
+          'Second assembly order should show availability warning as not enough inventory for its demand');
+    end;
+
+    [Test]
+    procedure AbleToAssembleConsidersDueDateAvailability()
+    var
+        AsmItem: Record Item;
+        CompItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        ItemJournalLine: Record "Item Journal Line";
+        AssemblyHeader: array[2] of Record "Assembly Header";
+        AssemblyLine: array[2] of Record "Assembly Line";
+        Item: Record Item;
+        GrossRequirement: Decimal;
+        ScheduledReceipt: Decimal;
+        ExpectedInventory: Decimal;
+        AvailableInventory: Decimal;
+        EarliestDate: Date;
+        AbleToAssemble: Decimal;
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [Able to Assemble] [Due Date]
+        // [SCENARIO] CalcAvailToAssemble on Assembly Line considers available inventory at due date,
+        // not all future demands that lower ExpectedInventory below zero.
+        Initialize();
+
+        // [GIVEN] Assembly item with component. Qty Per = 2
+        QtyPer := 2;
+        LibraryInventory.CreateItem(AsmItem);
+        AsmItem.Validate("Replenishment System", AsmItem."Replenishment System"::Assembly);
+        AsmItem.Modify(true);
+
+        LibraryInventory.CreateItem(CompItem);
+        LibraryInventory.CreateBOMComponent(
+          BOMComponent, AsmItem."No.", BOMComponent.Type::Item, CompItem."No.", QtyPer, CompItem."Base Unit of Measure");
+
+        // [GIVEN] Post 2 pcs of component to inventory
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, CompItem."No.", '', '', 2);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] First assembly order for 1 pc on WorkDate() + 5 (needs 2 components)
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[1], WorkDate() + 5, AsmItem."No.", '', 1, '');
+        FindAssemblyLine(AssemblyLine[1], AssemblyHeader[1], CompItem."No.");
+
+        // [GIVEN] Second assembly order for 3 pc on WorkDate() + 10 (needs 6 components - creates future demand)
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[2], WorkDate() + 10, AsmItem."No.", '', 3, '');
+        FindAssemblyLine(AssemblyLine[2], AssemblyHeader[2], CompItem."No.");
+
+        // [WHEN] Calculate availability to assemble for first assembly line
+        Item.Get(CompItem."No.");
+        AssemblyLine[1].CalcAvailToAssemble(
+          AssemblyHeader[1], Item, GrossRequirement, ScheduledReceipt, ExpectedInventory, AvailableInventory, EarliestDate, AbleToAssemble);
+
+        // [THEN] Able to Assemble should equal the remaining quantity of the header (1 in this case)
+        // because available inventory (2) >= remaining quantity base (2) at the due date
+        Assert.AreEqual(
+          AssemblyHeader[1]."Remaining Quantity", AbleToAssemble,
+          'Able to Assemble should be equal to the assembly order remaining quantity when inventory covers demand at due date');
+    end;
+
+    local procedure FindAssemblyLine(var AssemblyLine: Record "Assembly Line"; AssemblyHeader: Record "Assembly Header"; ItemNo: Code[20])
+    begin
+        AssemblyLine.SetRange("Document Type", AssemblyHeader."Document Type");
+        AssemblyLine.SetRange("Document No.", AssemblyHeader."No.");
+        AssemblyLine.SetRange("No.", ItemNo);
+        AssemblyLine.FindFirst();
+    end;
+}

