+codeunit 136399 "Job G/L Journal Amount LCY"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Job] [General Journal] [Amount (LCY)]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        Initialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AmountLCYValidationUpdatesJobCostFields()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        GLAccountNo: Code[20];
+        InitialAmount: Decimal;
+        NewAmountLCY: Decimal;
+        ExpectedJobUnitCost: Decimal;
+        ExpectedJobTotalCost: Decimal;
+    begin
+        // [SCENARIO] When Amount (LCY) is changed on a General Journal Line with a Job Task, Job Cost fields are updated.
+        // Bug: Changing Amount (LCY) field did not update Job Unit Cost, Job Unit Cost (LCY), Job Total Cost, and Job Total Cost (LCY).
+
+        // [GIVEN] A Job with Job Task and a G/L Journal Line with Job information and Job Quantity.
+        Initialize();
+        CreateJobWithJobTask(Job, JobTask);
+        CreateJobGLJournalBatch(GenJournalBatch);
+        GLAccountNo := LibraryERM.CreateGLAccountNo();
+
+        InitialAmount := LibraryRandom.RandDecInRange(100, 200, 2);
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice, GenJournalLine."Account Type"::"G/L Account",
+            GLAccountNo, InitialAmount);
+
+        GenJournalLine.Validate("Bal. Account Type", GenJournalLine."Bal. Account Type"::"G/L Account");
+        GenJournalLine.Validate("Bal. Account No.", LibraryERM.CreateGLAccountNo());
+        GenJournalLine.Validate("Job Line Type", GenJournalLine."Job Line Type"::"Both Budget and Billable");
+        GenJournalLine.Validate("Job No.", Job."No.");
+        GenJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        GenJournalLine.Validate("Job Quantity", LibraryRandom.RandDecInRange(1, 10, 2));
+        GenJournalLine.Modify(true);
+
+        // Store initial values to compare later
+        GenJournalLine.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name", GenJournalLine."Line No.");
+
+        // [WHEN] Amount (LCY) is changed to a new value.
+        NewAmountLCY := LibraryRandom.RandDecInRange(300, 500, 2);
+        GenJournalLine.Validate("Amount (LCY)", NewAmountLCY);
+        GenJournalLine.Modify(true);
+
+        // [THEN] Job Unit Cost, Job Unit Cost (LCY), Job Total Cost, and Job Total Cost (LCY) are updated based on the new Amount (LCY).
+        ExpectedJobUnitCost := NewAmountLCY / GenJournalLine."Job Quantity";
+        ExpectedJobTotalCost := NewAmountLCY;
+
+        GenJournalLine.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name", GenJournalLine."Line No.");
+        Assert.AreEqual(ExpectedJobUnitCost, GenJournalLine."Job Unit Cost (LCY)", 'Job Unit Cost (LCY) should be updated when Amount (LCY) changes.');
+        Assert.AreEqual(ExpectedJobTotalCost, GenJournalLine."Job Total Cost (LCY)", 'Job Total Cost (LCY) should be updated when Amount (LCY) changes.');
+        Assert.AreEqual(ExpectedJobUnitCost, GenJournalLine."Job Unit Cost", 'Job Unit Cost should be updated when Amount (LCY) changes.');
+        Assert.AreEqual(ExpectedJobTotalCost, GenJournalLine."Job Total Cost", 'Job Total Cost should be updated when Amount (LCY) changes.');
+
+        // Tear Down
+        GenJournalBatch.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name");
+        GenJournalBatch.Delete(true);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Job G/L Journal Amount LCY");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Job G/L Journal Amount LCY");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Job G/L Journal Amount LCY");
+    end;
+
+    local procedure CreateJobWithJobTask(var Job: Record Job; var JobTask: Record "Job Task")
+    begin
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+    end;
+
+    local procedure CreateJobGLJournalBatch(var GenJournalBatch: Record "Gen. Journal Batch")
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+    begin
+        GenJournalTemplate.SetRange(Type, GenJournalTemplate.Type::Jobs);
+        LibraryERM.FindGenJournalTemplate(GenJournalTemplate);
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, GenJournalTemplate.Name);
+    end;
+}

