diff --git a/test/SCMItemJournalUOMFix.Codeunit.al b/test/SCMItemJournalUOMFix.Codeunit.al
new file mode 100644
index 00000000..1cfb27e2
--- /dev/null
+++ b/test/SCMItemJournalUOMFix.Codeunit.al
@@ -0,0 +1,184 @@
+codeunit 99999 "SCM Item Journal UOM Fix"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item Journal] [Unit of Measure]
+    end;
+
+    var
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure UOMCodeClearedWhenItemNoChangedToDifferentItem()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        ItemUnitOfMeasure2: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] When changing Item No. on an Item Journal Line from one item to another with different UOM, 
+        // the Unit of Measure Code should be cleared and revalidated to prevent validation errors.
+        // Bug: After deleting item from Item Journal and adding a new item, the UOM was not being revalidated.
+        Initialize();
+
+        // [GIVEN] Two items with different base units of measure
+        CreateItemWithCustomBaseUOM(Item1, ItemUnitOfMeasure1, 'UOM1');
+        CreateItemWithCustomBaseUOM(Item2, ItemUnitOfMeasure2, 'UOM2');
+
+        // [GIVEN] An Item Journal Line with Item1 that has UOM1 as its Unit of Measure Code
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item1."No.", LibraryRandom.RandInt(10));
+
+        // [VERIFY] Initial setup - Item Journal Line should have UOM1
+        Assert.AreEqual(ItemUnitOfMeasure1.Code, ItemJournalLine."Unit of Measure Code",
+            'Initial Unit of Measure Code should be UOM1');
+
+        // [WHEN] User changes the Item No. from Item1 to Item2 (which has different UOM)
+        ItemJournalLine.Validate("Item No.", Item2."No.");
+
+        // [THEN] The Unit of Measure Code should be updated to Item2's base UOM (UOM2)
+        // Before the fix, this would retain UOM1 which is not valid for Item2, causing an error
+        Assert.AreEqual(ItemUnitOfMeasure2.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to the new item''s base UOM');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure UOMCodeClearedWhenItemNoChangedToItemWithoutSameUOM()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        AlternateUOM: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] When Item No. is changed and the previous UOM doesn't exist for the new item,
+        // the validation should succeed because UOM is cleared before setting new item.
+        Initialize();
+
+        // [GIVEN] Item1 with base UOM and an alternate UOM
+        CreateItemWithCustomBaseUOM(Item1, ItemUnitOfMeasure1, 'BASE1');
+        LibraryInventory.CreateItemUnitOfMeasureCode(AlternateUOM, Item1."No.", LibraryRandom.RandIntInRange(2, 5));
+
+        // [GIVEN] Item2 with a different base UOM and NO alternate UOM matching Item1's alternate
+        LibraryInventory.CreateItem(Item2);
+
+        // [GIVEN] An Item Journal Line with Item1 using the ALTERNATE UOM (not base)
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item1."No.", LibraryRandom.RandInt(10));
+        ItemJournalLine.Validate("Unit of Measure Code", AlternateUOM.Code);
+        ItemJournalLine.Modify(true);
+
+        // [VERIFY] The line now uses the alternate UOM from Item1
+        Assert.AreEqual(AlternateUOM.Code, ItemJournalLine."Unit of Measure Code",
+            'Item Journal Line should have alternate UOM from Item1');
+
+        // [WHEN] User changes the Item No. to Item2 (which does NOT have the alternate UOM)
+        // Before the fix: This would fail with "The field Unit of Measure Code ... contains a value that cannot be found"
+        ItemJournalLine.Validate("Item No.", Item2."No.");
+
+        // [THEN] The validation should succeed and UOM should be set to Item2's base UOM
+        Assert.AreEqual(Item2."Base Unit of Measure", ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to Item2''s base UOM');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure UOMCodePreservedWhenRevalidatingSameItem()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        AlternateUOM: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] When revalidating the same Item No. (no change), the UOM should be reset to base UOM.
+        // This is the existing behavior that should still work after the fix.
+        Initialize();
+
+        // [GIVEN] An Item with base UOM and an alternate UOM
+        CreateItemWithCustomBaseUOM(Item, ItemUnitOfMeasure, 'BASEUNIT');
+        LibraryInventory.CreateItemUnitOfMeasureCode(AlternateUOM, Item."No.", LibraryRandom.RandIntInRange(2, 5));
+
+        // [GIVEN] An Item Journal Line with the item using the ALTERNATE UOM
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LibraryRandom.RandInt(10));
+        ItemJournalLine.Validate("Unit of Measure Code", AlternateUOM.Code);
+        ItemJournalLine.Modify(true);
+
+        // [WHEN] User revalidates the same Item No.
+        ItemJournalLine.Validate("Item No.", Item."No.");
+
+        // [THEN] The UOM should be reset to the item's base UOM (standard behavior)
+        Assert.AreEqual(Item."Base Unit of Measure", ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be reset to base UOM when revalidating same item');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Item Journal UOM Fix");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Item Journal UOM Fix");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Item Journal UOM Fix");
+    end;
+
+    local procedure CreateItemWithCustomBaseUOM(var Item: Record Item; var ItemUnitOfMeasure: Record "Item Unit of Measure"; UOMCode: Code[10])
+    var
+        UnitOfMeasure: Record "Unit of Measure";
+    begin
+        // Create the unit of measure if it doesn't exist
+        if not UnitOfMeasure.Get(UOMCode) then begin
+            UnitOfMeasure.Init();
+            UnitOfMeasure.Code := UOMCode;
+            UnitOfMeasure.Description := UOMCode;
+            UnitOfMeasure.Insert(true);
+        end;
+
+        // Create the item
+        LibraryInventory.CreateItem(Item);
+
+        // Create the item unit of measure
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UOMCode, 1);
+
+        // Set as base unit of measure
+        Item.Validate("Base Unit of Measure", UOMCode);
+        Item.Modify(true);
+    end;
+
+    local procedure SelectItemJournal(var ItemJournalBatch: Record "Item Journal Batch")
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al
new file mode 100644
index 00000000..4a03fc35
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al
@@ -0,0 +1,95 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+using Microsoft.Foundation.UOM;
+
+codeunit 137901 "SCM Prod Order Qty Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryUtility: Codeunit "Library - Utility";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ComponentQtyPerNotZeroWhenUOMHasRoundingPrecision()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodsItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QuantityPerInBOM: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Prod. Order Component] [Rounding Precision]
+        // [SCENARIO] When a component's Item UOM has Qty. Rounding Precision = 1 and the Production BOM 
+        // specifies a partial Quantity Per (e.g., 0.09), the Prod. Order Component should retain the 
+        // correct Quantity Per value instead of rounding to 0.
+
+        // [GIVEN] A component item with Rounding Precision = 0.01 
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] The component's Item Unit of Measure has Qty. Rounding Precision = 1
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] A finished goods item with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(FinishedGoodsItem);
+        FinishedGoodsItem.Validate("Replenishment System", FinishedGoodsItem."Replenishment System"::"Prod. Order");
+        FinishedGoodsItem.Validate("Rounding Precision", 1);
+        FinishedGoodsItem.Modify(true);
+
+        // [GIVEN] A Production BOM with the component item having Quantity Per = 0.09
+        QuantityPerInBOM := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FinishedGoodsItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPerInBOM);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] The finished goods item is assigned the Production BOM
+        FinishedGoodsItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodsItem.Modify(true);
+
+        // [WHEN] A Released Production Order is created and refreshed for the finished goods item with Quantity = 1
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder,
+            ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item,
+            FinishedGoodsItem."No.",
+            1);
+
+        // [THEN] The Prod. Order Component has Quantity per = 0.09 (not 0)
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        Assert.AreEqual(
+            QuantityPerInBOM,
+            ProdOrderComponent."Quantity per",
+            'Quantity per should match the BOM value and not be rounded to 0');
+
+        // [THEN] The Expected Quantity should also be 0.09 (Quantity per * Prod Order Quantity = 0.09 * 1 = 0.09)
+        Assert.AreEqual(
+            QuantityPerInBOM,
+            ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should match the BOM value and not be rounded to 0');
+    end;
+}

