+    procedure InvoiceDiscountPreservedWhenCurrencyFactorChangesWithoutLineDiscount()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        Currency: Record Currency;
+        Customer: Record Customer;
+        InitialInvDiscountAmount: Decimal;
+        NewExchangeRateDate: Date;
+    begin
+        // [FEATURE] [Invoice Discount] [FCY] [Currency Factor]
+        // [SCENARIO] Invoice Discount Amount should be preserved when Currency Factor changes
+        //            due to posting date change, when the Sales Line has no Line Discount %.
+
+        // [GIVEN] Create Currency with two Exchange Rates on different dates
+        Initialize();
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.SetCurrencyGainLossAccounts(Currency);
+        LibraryERM.CreateExchRate(CurrencyExchangeRate, Currency.Code, WorkDate());
+        CurrencyExchangeRate.Validate("Exchange Rate Amount", 100);
+        CurrencyExchangeRate.Validate("Adjustment Exch. Rate Amount", 100);
+        CurrencyExchangeRate.Validate("Relational Exch. Rate Amount", 50);
+        CurrencyExchangeRate.Validate("Relational Adjmt Exch Rate Amt", 50);
+        CurrencyExchangeRate.Modify(true);
+
+        NewExchangeRateDate := CalcDate('<+14D>', WorkDate());
+        LibraryERM.CreateExchRate(CurrencyExchangeRate, Currency.Code, NewExchangeRateDate);
+        CurrencyExchangeRate.Validate("Exchange Rate Amount", 100);
+        CurrencyExchangeRate.Validate("Adjustment Exch. Rate Amount", 100);
+        CurrencyExchangeRate.Validate("Relational Exch. Rate Amount", 60);
+        CurrencyExchangeRate.Validate("Relational Adjmt Exch Rate Amt", 60);
+        CurrencyExchangeRate.Modify(true);
+
+        // [GIVEN] Create a Customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Create Sales Order with Currency and a single Sales Line with Unit Price but NO Line Discount
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        SalesHeader.Validate("Currency Code", Currency.Code);
+        SalesHeader.Modify(true);
