+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Requisition;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+using System.TestLibraries.Utilities;
+
+codeunit 137099 "SCM Planning Multi Subassembly"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PlanningNoLinesForItemUsedInMultipleSubassemblies()
+    var
+        TopLevelItem: Record Item;
+        SubassemblyA: Record Item;
+        SubassemblyB: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeaderTop: Record "Production BOM Header";
+        ProductionBOMHeaderSubA: Record "Production BOM Header";
+        ProductionBOMHeaderSubB: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // [FEATURE] [Planning] [Production BOM] [Make-to-Order]
+        // [SCENARIO 530025] When a component item is used in multiple subassemblies under a single production order, 
+        // planning should not create unnecessary lines when supply equals demand.
+        Initialize();
+
+        // [GIVEN] Create Component Item "C" with Make-to-Order manufacturing policy
+        CreateMakeToOrderProdItem(ComponentItem);
+
+        // [GIVEN] Create Subassembly Items "A" and "B" with Make-to-Order manufacturing policy
+        CreateMakeToOrderProdItem(SubassemblyA);
+        CreateMakeToOrderProdItem(SubassemblyB);
+
+        // [GIVEN] Create Top Level Item "T" with Make-to-Order manufacturing policy
+        CreateMakeToOrderProdItem(TopLevelItem);
+
+        // [GIVEN] Create Production BOM for Subassembly A containing Component Item (Qty per = 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderSubA, SubassemblyA."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderSubA, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeaderSubA, ProductionBOMHeaderSubA.Status::Certified);
+        SubassemblyA.Validate("Production BOM No.", ProductionBOMHeaderSubA."No.");
+        SubassemblyA.Modify(true);
+
+        // [GIVEN] Create Production BOM for Subassembly B containing Component Item (Qty per = 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderSubB, SubassemblyB."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderSubB, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeaderSubB, ProductionBOMHeaderSubB.Status::Certified);
+        SubassemblyB.Validate("Production BOM No.", ProductionBOMHeaderSubB."No.");
+        SubassemblyB.Modify(true);
+
+        // [GIVEN] Create Production BOM for Top Level Item containing both Subassembly A and B (Qty per = 1 each)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderTop, TopLevelItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderTop, ProductionBOMLine, '', ProductionBOMLine.Type::Item, SubassemblyA."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderTop, ProductionBOMLine, '', ProductionBOMLine.Type::Item, SubassemblyB."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeaderTop, ProductionBOMHeaderTop.Status::Certified);
+        TopLevelItem.Validate("Production BOM No.", ProductionBOMHeaderTop."No.");
+        TopLevelItem.Modify(true);
+
+        // [GIVEN] Create Released Production Order for Top Level Item with quantity = 1 and refresh it
+        // This creates demand for Component Item of 2 (1 from Subassembly A + 1 from Subassembly B)
+        // And creates supply (Prod Order Line) for Component Item of 2
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, TopLevelItem."No.", 1);
+
+        // [WHEN] Calculate Regenerative Plan for Component Item
+        ComponentItem.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(ComponentItem, WorkDate(), CalcDate('<CY>', WorkDate()));
+
+        // [THEN] No planning lines should be created for Component Item because supply equals demand
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ComponentItem."No.");
+        Assert.RecordIsEmpty(RequisitionLine);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Planning Multi Subassembly");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Planning Multi Subassembly");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Planning Multi Subassembly");
+    end;
+
+    local procedure CreateMakeToOrderProdItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Manufacturing Policy", Item."Manufacturing Policy"::"Make-to-Order");
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Modify(true);
+    end;
+}

