+    [Test]
+    [HandlerFunctions('PurchOrderFromJobModalPageHandler')]
+    procedure CreatePurchaseOrderFromJobWithPlanningLinesInsertedBeforeExisting()
+    var
+        Vendor: Record Vendor;
+        Items: array[2] of Record Item;
+        JobPlanningLines: array[2] of Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+        PurchaseOrder: TestPage "Purchase Order";
+        JobCard: TestPage "Job Card";
+    begin
+        // [SCENARIO] Verify Create Purchase Order from Project works when Project Planning Lines are added before the previous ones
+        // This tests the fix for the issue where adding a new line BEFORE existing lines causes
+        // the "Demand Line No." filter to be built incorrectly (e.g., "16..15" instead of "15..16")
+        Initialize();
+
+        // [GIVEN] Create Vendor
+        LibraryPurchase.CreateVendor(Vendor);
+
+        // [GIVEN] Create two Items without inventory
+        LibraryInventory.CreateItem(Items[1]);
+        LibraryInventory.CreateItem(Items[2]);
+
+        // [GIVEN] Create Job with Job Task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] Create first Job Planning Line at a higher Line No. (20000)
+        // This line will get a LOWER Job Contract Entry No. because it's created first
+        JobPlanningLines[1].Init();
+        JobPlanningLines[1].Validate("Job No.", JobTask."Job No.");
+        JobPlanningLines[1].Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLines[1].Validate("Line No.", 20000);
+        JobPlanningLines[1].Insert(true);
+        JobPlanningLines[1].Validate("Planning Date", WorkDate());
+        JobPlanningLines[1].Validate("Line Type", JobPlanningLines[1]."Line Type"::"Both Budget and Billable");
+        JobPlanningLines[1].Validate(Type, JobPlanningLines[1].Type::Item);
+        JobPlanningLines[1].Validate("No.", Items[1]."No.");
+        JobPlanningLines[1].Validate(Quantity, 10);
+        JobPlanningLines[1].Modify(true);
+
+        // [GIVEN] Create second Job Planning Line at a lower Line No. (10000) - simulating insertion BEFORE existing line
+        // This line will get a HIGHER Job Contract Entry No. because it's created second
+        // When iterating by Line No. (primary key), the order will be 10000->20000
+        // But the Job Contract Entry No. order will be the opposite
+        // Without the fix, this causes the filter to be built as "higher..lower" which is an empty range
+        JobPlanningLines[2].Init();
+        JobPlanningLines[2].Validate("Job No.", JobTask."Job No.");
+        JobPlanningLines[2].Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLines[2].Validate("Line No.", 10000);
+        JobPlanningLines[2].Insert(true);
+        JobPlanningLines[2].Validate("Planning Date", WorkDate());
+        JobPlanningLines[2].Validate("Line Type", JobPlanningLines[2]."Line Type"::"Both Budget and Billable");
+        JobPlanningLines[2].Validate(Type, JobPlanningLines[2].Type::Item);
+        JobPlanningLines[2].Validate("No.", Items[2]."No.");
+        JobPlanningLines[2].Validate(Quantity, 10);
+        JobPlanningLines[2].Modify(true);
+
+        // [WHEN] Create Purchase Order from Job Card
+        LibraryVariableStorage.Enqueue(Vendor."No.");
+        LibraryVariableStorage.Enqueue(Vendor."No.");
+        PurchaseOrder.Trap();
+        JobCard.OpenEdit();
+        JobCard.GotoRecord(Job);
+        JobCard.CreatePurchaseOrder.Invoke();
+
+        // [THEN] Purchase lines should be created for BOTH items
+        // Without the fix, no purchase lines would be created because the filter was invalid
+        PurchaseLine.SetRange("Job No.", Job."No.");
+        PurchaseLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        Assert.AreEqual(2, PurchaseLine.Count, 'Expected 2 purchase lines to be created for both Job Planning Lines');
+
+        // [THEN] Verify purchase line exists for first item
+        PurchaseLine.SetRange("No.", Items[1]."No.");
+        Assert.IsFalse(PurchaseLine.IsEmpty, 'Purchase Line should be created for first Item');
+
+        // [THEN] Verify purchase line exists for second item
+        PurchaseLine.SetRange("No.", Items[2]."No.");
+        Assert.IsFalse(PurchaseLine.IsEmpty, 'Purchase Line should be created for second Item');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

