+    [Test]
+    procedure RolledUpCapacityCostSameForEmptyBOMAndNoBOM()
+    var
+        ParentItem: Record Item;
+        CompItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        EmptyProductionBOMHeader: Record "Production BOM Header";
+        BOMBuffer: Record "BOM Buffer";
+        BOMCostShares: TestPage "BOM Cost Shares";
+        RolledUpCapacityCostWithEmptyBOM: Decimal;
+        RolledUpCapacityCostWithNoBOM: Decimal;
+        QtyPer: Decimal;
+    begin
+        // [FEATURE] [BOM Cost Share] [Production BOM]
+        // [SCENARIO] Rolled-up Capacity Cost for a component is the same when component has an empty BOM vs no BOM
+        // When a production item has an empty Production BOM (no lines) vs no Production BOM at all,
+        // the Rolled-up Capacity Cost on the BOM Cost Shares page should be consistent.
+        Initialize();
+
+        QtyPer := LibraryRandom.RandIntInRange(2, 5);
+
+        // [GIVEN] Create component item "C" with Replenishment System = "Prod. Order" and Unit Cost
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::"Prod. Order");
+        CompItem.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 50, 2));
+        CompItem.Modify(true);
+
+        // [GIVEN] Create parent item "P" with Production BOM containing component "C" with Qty per > 1
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create an empty certified Production BOM (no lines) and assign it to component "C"
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyProductionBOMHeader, CompItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(EmptyProductionBOMHeader, EmptyProductionBOMHeader.Status::Certified);
+        CompItem.Validate("Production BOM No.", EmptyProductionBOMHeader."No.");
+        CompItem.Modify(true);
+
+        // [WHEN] Open BOM Cost Shares page for parent item "P" (component has empty BOM)
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+
+        // [THEN] Get Rolled-up Capacity Cost for component "C"
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapacityCostWithEmptyBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [GIVEN] Remove the Production BOM from component "C" (now has no BOM at all)
+        CompItem.Validate("Production BOM No.", '');
+        CompItem.Modify(true);
+
+        // [WHEN] Open BOM Cost Shares page for parent item "P" again (component has no BOM)
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+
+        // [THEN] Get Rolled-up Capacity Cost for component "C"
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapacityCostWithNoBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [THEN] Rolled-up Capacity Cost is the same in both cases (empty BOM = no BOM)
+        Assert.AreEqual(
+          RolledUpCapacityCostWithEmptyBOM, RolledUpCapacityCostWithNoBOM,
+          'Rolled-up Capacity Cost should be the same for empty BOM and no BOM');
+    end;
