+        ReservationEntry: Record "Reservation Entry";
+        ItemJournalLine: Record "Item Journal Line";
+        SalesGetShipment: Codeunit "Sales-Get Shipment";
+        LotNo: Code[50];
+        OriginalQty: Decimal;
+        ReducedQty: Decimal;
+    begin
+        // [SCENARIO] When quantity on a sales invoice line (created via Get Shipment Lines) is reduced,
+        // item tracking lines should be preserved for items with Reserve = Always and lot tracking.
+        // This verifies the fix where CheckQuantityReducedOnSalesLine returns false when ShipmentExists.
+        Initialize();
+
+        // [GIVEN] Item with Lot Tracking Code and Reserve = Always
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Modify(true);
+
+        // [GIVEN] Add inventory with lot tracking
+        OriginalQty := 3;
+        LotNo := LibraryUtility.GenerateGUID();
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", '', '', OriginalQty);
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, OriginalQty);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Create and ship a Sales Order with item tracking
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", OriginalQty);
+        LibraryItemTracking.CreateSalesOrderItemTracking(ReservationEntry, SalesLine, '', LotNo, -OriginalQty);
+        LibrarySales.PostSalesDocument(SalesHeader, true, false); // Ship only
+
+        // [GIVEN] Create a Sales Invoice and get shipment lines
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesShipmentLine.SetRange("Sell-to Customer No.", Customer."No.");
+        SalesShipmentLine.SetRange("No.", Item."No.");
+        SalesGetShipment.SetSalesHeader(SalesHeaderInvoice);
+        SalesGetShipment.CreateInvLines(SalesShipmentLine);
+
+        // [GIVEN] Find the created sales invoice line
+        SalesLineInvoice.SetRange("Document Type", SalesHeaderInvoice."Document Type");
+        SalesLineInvoice.SetRange("Document No.", SalesHeaderInvoice."No.");
+        SalesLineInvoice.SetRange(Type, SalesLineInvoice.Type::Item);
+        SalesLineInvoice.SetRange("No.", Item."No.");
+        SalesLineInvoice.FindFirst();
+
+        // Verify that item tracking exists on invoice line before reducing quantity
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", DATABASE::"Sales Line");
+        ReservationEntry.SetRange("Source Subtype", SalesLineInvoice."Document Type".AsInteger());
+        ReservationEntry.SetRange("Source ID", SalesLineInvoice."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLineInvoice."Line No.");
+        Assert.IsFalse(ReservationEntry.IsEmpty(), 'Item tracking should exist before quantity reduction');
+
+        // [WHEN] Reduce the quantity on the sales invoice line
+        ReducedQty := OriginalQty - 1;
+        SalesLineInvoice.Validate(Quantity, ReducedQty);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking lines should still exist on the sales invoice line
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", DATABASE::"Sales Line");
+        ReservationEntry.SetRange("Source Subtype", SalesLineInvoice."Document Type".AsInteger());
+        ReservationEntry.SetRange("Source ID", SalesLineInvoice."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", SalesLineInvoice."Line No.");
+        Assert.IsFalse(ReservationEntry.IsEmpty(), 'Item tracking should be preserved after quantity reduction on Get Shipment Lines invoice');
+
+        // [THEN] Verify the lot number is still correctly assigned
+        ReservationEntry.FindFirst();
+        ReservationEntry.TestField("Lot No.", LotNo);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

