+codeunit 136290 "Contact Next Task Date"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Marketing] [Contact] [Task]
+    end;
+
+    var
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateShowsOrganizerTasks()
+    var
+        Contact: Record Contact;
+        Task: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact should display tasks with System To-do Type = Organizer
+        // [GIVEN] A Person Contact with a Company No.
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+        LibraryMarketing.CreatePersonContactWithCompanyNo(Contact);
