+        Contact: Record Contact;
+        Task: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact should display tasks with System To-do Type = Contact Attendee
