+
+        // [THEN] Next Task Date shows the task date
+        Assert.AreEqual(TaskDate, Contact."Next Task Date", 'Next Task Date should show Contact Attendee task date');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateShowsEarliestOfOrganizerAndContactAttendee()
+    var
+        Contact: Record Contact;
+        OrganizerTask: Record "To-do";
+        ContactAttendeeTask: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        OrganizerTaskDate: Date;
+        ContactAttendeeTaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact should show the earliest date between Organizer and Contact Attendee tasks
+        // [GIVEN] A Person Contact with a Company No.
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+        LibraryMarketing.CreatePersonContactWithCompanyNo(Contact);
+
+        // [GIVEN] An Organizer Task with earlier date
+        OrganizerTaskDate := WorkDate() + 5;
+        CreateTaskWithSystemType(
+            OrganizerTask,
+            Contact."Company No.",
+            Contact."No.",
+            SalespersonPurchaser.Code,
+            OrganizerTaskDate,
+            OrganizerTask."System To-do Type"::Organizer);
+
+        // [GIVEN] A Contact Attendee Task with later date
+        ContactAttendeeTaskDate := WorkDate() + 15;
+        CreateTaskWithSystemType(
+            ContactAttendeeTask,
+            Contact."Company No.",
+            Contact."No.",
+            SalespersonPurchaser.Code,
+            ContactAttendeeTaskDate,
+            ContactAttendeeTask."System To-do Type"::"Contact Attendee");
+
+        // [WHEN] CalcFields on Next Task Date
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] Next Task Date shows the earliest task date (Organizer)
+        Assert.AreEqual(OrganizerTaskDate, Contact."Next Task Date", 'Next Task Date should show the earliest task date');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateExcludesClosedTasks()
+    var
+        Contact: Record Contact;
+        Task: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact should not display closed tasks
+        // [GIVEN] A Person Contact with a Company No.
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+        LibraryMarketing.CreatePersonContactWithCompanyNo(Contact);
+
+        // [GIVEN] A closed Task with System To-do Type = Organizer linked to the Contact
+        TaskDate := WorkDate() + 10;
+        CreateTaskWithSystemType(
+            Task,
+            Contact."Company No.",
+            Contact."No.",
+            SalespersonPurchaser.Code,
+            TaskDate,
+            Task."System To-do Type"::Organizer);
+        Task.Validate(Closed, true);
+        Task.Modify(true);
+
+        // [WHEN] CalcFields on Next Task Date
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] Next Task Date is empty
+        Assert.AreEqual(0D, Contact."Next Task Date", 'Next Task Date should be empty for closed tasks');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateExcludesSalespersonAttendeeTasks()
+    var
+        Contact: Record Contact;
+        Task: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact should not display tasks with System To-do Type = Salesperson Attendee
+        // [GIVEN] A Person Contact with a Company No.
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+        LibraryMarketing.CreatePersonContactWithCompanyNo(Contact);
+
+        // [GIVEN] A Task with System To-do Type = Salesperson Attendee linked to the Contact
+        TaskDate := WorkDate() + 10;
+        CreateTaskWithSystemType(
+            Task,
+            Contact."Company No.",
+            Contact."No.",
+            SalespersonPurchaser.Code,
+            TaskDate,
+            Task."System To-do Type"::"Salesperson Attendee");
+
+        // [WHEN] CalcFields on Next Task Date
+        Contact.CalcFields("Next Task Date");
+
+        // [THEN] Next Task Date is empty (Salesperson Attendee tasks should not be included)
+        Assert.AreEqual(0D, Contact."Next Task Date", 'Next Task Date should not show Salesperson Attendee tasks');
+    end;
+
+    local procedure CreateTaskWithSystemType(var Task: Record "To-do"; ContactCompanyNo: Code[20]; ContactNo: Code[20]; SalespersonCode: Code[20]; TaskDate: Date; SystemToDoType: Option)
+    begin
+        Task.Init();
+        Task.Validate(Date, TaskDate);
+        Task.Validate("Contact Company No.", ContactCompanyNo);
+        Task.Validate("Contact No.", ContactNo);
+        Task.Validate("Salesperson Code", SalespersonCode);
+        Task.Validate(Type, Task.Type::"Phone Call");
+        Task.Validate(Description, 'Test Task');
+        Task."System To-do Type" := SystemToDoType;
+        Task.Insert(true);
+    end;
+}

