diff --git a/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
new file mode 100644
index 00000000..6c18c11b
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
@@ -0,0 +1,171 @@
+codeunit 139445 "Issued Reminder Email Tests"
+{
+    // [FEATURE] [Issued Reminder] [Email] [Sent Email History]
+    // Tests that issued reminder emails are properly logged in customer's sent email history
+
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+    EventSubscriberInstance = Manual;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryUtility: Codeunit "Library - Utility";
+        IsInitialized: Boolean;
+        CapturedSourceTableIDs: List of [Integer];
+        CapturedSourceIDs: List of [Guid];
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderHeaderIsRecognizedAsCustomerAccount()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+        IssuedReminderEmailTests: Codeunit "Issued Reminder Email Tests";
+    begin
+        // [SCENARIO] When sending an issued reminder email, the customer should be added to email source relations
+        // so that the email appears in the customer's sent email history.
+        Initialize();
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] An issued reminder header for that customer
+        CreateIssuedReminderHeader(IssuedReminderHeader, Customer);
+
+        // [WHEN] We subscribe to capture the source table IDs when sending email
+        BindSubscription(IssuedReminderEmailTests);
+        IssuedReminderEmailTests.ClearCapturedData();
+
+        // Trigger the email sending logic that populates source relations
+        IssuedReminderHeader.SetRecFilter();
+
+        // Call SendEmailToCust which internally calls SendEmailDirectly
+        // This will trigger our event subscriber to capture SourceTableIDs
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            true,  // ShowDialog = true to trigger direct sending path
+            Customer."No.");
+
+        UnbindSubscription(IssuedReminderEmailTests);
+
+        // [THEN] The captured source table IDs should include Database::Customer
+        IssuedReminderEmailTests.GetCapturedData(CapturedSourceTableIDs, CapturedSourceIDs);
+        Assert.IsTrue(
+            CapturedSourceTableIDs.Contains(Database::Customer),
+            'Customer table should be included in email source relations for issued reminder');
+
+        // [THEN] The customer's SystemId should be in the captured source IDs
+        Assert.IsTrue(
+            CapturedSourceIDs.Contains(Customer.SystemId),
+            'Customer SystemId should be included in email source IDs for issued reminder');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderUsesCustomerNoFieldForEmailRelation()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+        IssuedReminderEmailTests: Codeunit "Issued Reminder Email Tests";
+    begin
+        // [SCENARIO] Issued Reminder Header uses "Customer No." field (not "Sell-to Customer No.")
+        // to identify the customer for email source relations.
+        Initialize();
+
+        // [GIVEN] A customer with a specific No.
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] An issued reminder header linked to that customer via "Customer No." field
+        CreateIssuedReminderHeader(IssuedReminderHeader, Customer);
+
+        // [WHEN] We send an email for the issued reminder
+        BindSubscription(IssuedReminderEmailTests);
+        IssuedReminderEmailTests.ClearCapturedData();
+
+        IssuedReminderHeader.SetRecFilter();
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            true,
+            Customer."No.");
+
+        UnbindSubscription(IssuedReminderEmailTests);
+
+        // [THEN] The customer should be correctly identified and included in source relations
+        // This verifies that the code uses "Customer No." field instead of "Sell-to Customer No."
+        IssuedReminderEmailTests.GetCapturedData(CapturedSourceTableIDs, CapturedSourceIDs);
+
+        Assert.IsTrue(
+            CapturedSourceTableIDs.Contains(Database::Customer),
+            'Customer should be identified using Customer No. field from Issued Reminder Header');
+
+        Assert.IsTrue(
+            CapturedSourceIDs.Contains(Customer.SystemId),
+            'Correct customer should be linked to email based on Customer No. field');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryWorkflow: Codeunit "Library - Workflow";
+    begin
+        if IsInitialized then
+            exit;
+
+        LibraryWorkflow.SetUpEmailAccount();
+        IsInitialized := true;
+    end;
+
+    local procedure CreateIssuedReminderHeader(var IssuedReminderHeader: Record "Issued Reminder Header"; Customer: Record Customer)
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+    begin
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader.Validate(
+            "No.",
+            LibraryUtility.GenerateRandomCode(IssuedReminderHeader.FieldNo("No."), Database::"Issued Reminder Header"));
+        IssuedReminderHeader.Validate("Customer No.", Customer."No.");
+        IssuedReminderHeader.Validate("Customer Posting Group", Customer."Customer Posting Group");
+
+        LibraryERM.FindVATPostingSetup(VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT");
+        IssuedReminderHeader.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        IssuedReminderHeader.Insert(true);
+    end;
+
+    procedure ClearCapturedData()
+    begin
+        Clear(CapturedSourceTableIDs);
+        Clear(CapturedSourceIDs);
+    end;
+
+    procedure GetCapturedData(var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid])
+    begin
+        SourceTableIDs := CapturedSourceTableIDs;
+        SourceIDs := CapturedSourceIDs;
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", OnSendEmailDirectlyOnBeforeSend, '', false, false)]
+    local procedure OnSendEmailDirectlyOnBeforeSend(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    var
+        i: Integer;
+    begin
+        // Capture the source table IDs and source IDs for verification
+        for i := 1 to SourceTableIDs.Count() do
+            CapturedSourceTableIDs.Add(SourceTableIDs.Get(i));
+
+        for i := 1 to SourceIDs.Count() do
+            CapturedSourceIDs.Add(SourceIDs.Get(i));
+
+        // Set IsHandled to prevent actual email sending during test
+        IsHandled := true;
+        AllEmailsWereSuccessful := true;
+    end;
+}

