+codeunit 139999 "Job Reserv. Non-Inv Item Test"
+{
+    // Tests that non-inventory and service items cannot be reserved for job planning lines.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+        NonInvReserveTypeErr: Label 'Non-inventory and service items cannot be reserved.';
+
+    [Test]
+    [HandlerFunctions('ReservationPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReserveNonInventoryItemForJobPlanningLineRaisesError()
+    var
+        Item: Record Item;
+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] Reservation should not be allowed for non-inventory items on job planning lines
+        // [FEATURE] [Reservation] [Job] [Non-Inventory Item]
+
+        // [GIVEN] A non-inventory type item
+        Initialize();
+        LibraryInventory.CreateNonInventoryTypeItem(Item);
+
+        // [GIVEN] A purchase order with the non-inventory item
+        CreatePurchaseDocumentWithItem(PurchaseLine, Item."No.");
+
+        // [GIVEN] A job planning line with the same non-inventory item
+        CreateJobAndPlanningLine(JobPlanningLine, Item."No.", PurchaseLine.Quantity);
+
+        // [WHEN] Trying to reserve the purchase order against the job planning line
+        asserterror PurchaseLine.ShowReservation();
+
+        // [THEN] An error is raised indicating that non-inventory items cannot be reserved
+        Assert.ExpectedError(NonInvReserveTypeErr);
+    end;
+
+    [Test]
+    [HandlerFunctions('ReservationPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReserveServiceItemForJobPlanningLineRaisesError()
+    var
+        Item: Record Item;
+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] Reservation should not be allowed for service items on job planning lines
+        // [FEATURE] [Reservation] [Job] [Service Item]
+
+        // [GIVEN] A service type item
+        Initialize();
+        LibraryInventory.CreateServiceTypeItem(Item);
+
+        // [GIVEN] A purchase order with the service item
+        CreatePurchaseDocumentWithItem(PurchaseLine, Item."No.");
+
+        // [GIVEN] A job planning line with the same service item
+        CreateJobAndPlanningLine(JobPlanningLine, Item."No.", PurchaseLine.Quantity);
+
+        // [WHEN] Trying to reserve the purchase order against the job planning line
+        asserterror PurchaseLine.ShowReservation();
+
+        // [THEN] An error is raised indicating that service items cannot be reserved
+        Assert.ExpectedError(NonInvReserveTypeErr);
+    end;
+
+    [Test]
+    [HandlerFunctions('ReservationPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReserveInventoryItemForJobPlanningLineSucceeds()
+    var
+        Item: Record Item;
+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] Reservation should be allowed for inventory items on job planning lines
+        // [FEATURE] [Reservation] [Job] [Inventory Item]
+
+        // [GIVEN] An inventory type item
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] A purchase order with the inventory item
+        CreatePurchaseDocumentWithItem(PurchaseLine, Item."No.");
+
+        // [GIVEN] A job planning line with the same inventory item
+        CreateJobAndPlanningLine(JobPlanningLine, Item."No.", PurchaseLine.Quantity);
+
+        // [WHEN] Reserving the purchase order against the job planning line
+        PurchaseLine.ShowReservation();
+
+        // [THEN] The reservation is created successfully
+        PurchaseLine.CalcFields("Reserved Quantity");
+        Assert.IsTrue(PurchaseLine."Reserved Quantity" > 0, 'Reservation should be created for inventory items');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        DummyJobsSetup: Record "Jobs Setup";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Job Reserv. Non-Inv Item Test");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Job Reserv. Non-Inv Item Test");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        DummyJobsSetup."Allow Sched/Contract Lines Def" := false;
+        DummyJobsSetup."Apply Usage Link by Default" := false;
+        DummyJobsSetup.Modify();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Job Reserv. Non-Inv Item Test");
+    end;
+
+    local procedure CreatePurchaseDocumentWithItem(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    var
+        PurchaseHeader: Record "Purchase Header";
+        Vendor: Record Vendor;
+    begin
+        LibraryPurchase.CreateVendor(Vendor);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Vendor."No.");
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, ItemNo, LibraryRandom.RandDecInRange(5, 10, 2));
+    end;
+
+    local procedure CreateJobAndPlanningLine(var JobPlanningLine: Record "Job Planning Line"; ItemNo: Code[20]; Quantity: Decimal)
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+    begin
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        LibraryJob.CreateJobPlanningLine(JobPlanningLine."Line Type"::Budget, JobPlanningLine.Type::Item, JobTask, JobPlanningLine);
+        JobPlanningLine.Validate("No.", ItemNo);
+        JobPlanningLine.Validate("Planning Date", CalcDate('<+6M>', WorkDate()));
+        JobPlanningLine.Validate("Usage Link", true);
+        JobPlanningLine.Validate(Quantity, Quantity);
+        JobPlanningLine.Validate(Reserve, JobPlanningLine.Reserve::Optional);
+        JobPlanningLine.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ReservationPageHandler(var Reservation: TestPage Reservation)
+    begin
+        Reservation."Auto Reserve".Invoke();
+        Reservation.OK().Invoke();
+    end;
+}

