+    procedure OpenJnl_ReqJnlManagement_UsesFieldValueNotFilter()
+    var
+        ReqWkshTemplate: array[2] of Record "Req. Wksh. Template";
+        RequisitionWkshName: array[2] of Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        ReqJnlManagement: Codeunit ReqJnlManagement;
+        CurrentJnlBatchName: Code[10];
+    begin
+        // [FEATURE] [Requisition Worksheet] [Planning]
+        // [SCENARIO] When opening Planning Worksheet from Item Availability by Event,
+        // ReqJnlManagement.OpenJnl should use the Worksheet Template Name field value
+        // to determine the correct batch, not the filter value (which may be the last used template)
+
+        // [GIVEN] Two templates with two different batches
+        CreateReqWorksheetTemplate(ReqWkshTemplate[1]);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName[1], ReqWkshTemplate[1].Name);
+        CreateReqWorksheetTemplate(ReqWkshTemplate[2]);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName[2], ReqWkshTemplate[2].Name);
+
+        // [GIVEN] A requisition line with filter pointing to template 2 (last used template)
+        // but field values set to template 1 (the actual line we want to navigate to)
+        // This simulates the scenario where user last opened template 2, but navigates from
+        // Item Availability by Event to a line in template 1
+        Clear(RequisitionLine);
+        RequisitionLine.FilterGroup(2);
+        RequisitionLine.SetRange("Worksheet Template Name", ReqWkshTemplate[2].Name);
+        RequisitionLine.FilterGroup(0);
+
+        // [GIVEN] The record field values are set to template 1 (navigation target)
+        RequisitionLine."Worksheet Template Name" := ReqWkshTemplate[1].Name;
+        RequisitionLine."Journal Batch Name" := RequisitionWkshName[1].Name;
+
+        // [WHEN] OpenJnl is called with the batch from template 1
+        CurrentJnlBatchName := RequisitionLine."Journal Batch Name";
+        ReqJnlManagement.OpenJnl(CurrentJnlBatchName, RequisitionLine);
+
+        // [THEN] The batch name should be from template 1 (from field value), not template 2 (from filter)
+        // Without the fix, this would fail because GetRangeMax returns template 2 and CheckTemplateName
+        // would override CurrentJnlBatchName with a batch from template 2
+        Assert.AreEqual(RequisitionWkshName[1].Name, CurrentJnlBatchName,
+            'OpenJnl should use the batch from the Worksheet Template Name field value');
+    end;
