+        ReservEntry1: Record "Reservation Entry";
+        ReservEntry2: Record "Reservation Entry";
+        ReservEntry3: Record "Reservation Entry";
+        UnitOfMeasure: Record "Unit of Measure";
+        TotalQuantity: Decimal;
+        ExpectedQty: Decimal;
+        QtyPerUOM: Decimal;
+        BaseQty1: Decimal;
+        BaseQty2: Decimal;
+        BaseQty3: Decimal;
+        SourceID: Code[20];
+        SourceRefNo: Integer;
+    begin
+        // [FEATURE] [Order Tracking] [UOM]
+        // [SCENARIO] When multiple tracking reservation entries exist with non-base UOM,
+        // the sum of calculated Quantity field should be correct without rounding errors.
+        // This test verifies the fix where CalcReservationQuantity includes Tracking status entries.
+
+        // [GIVEN] An item with a non-base UOM (e.g., CASE = 24 PCS)
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+
+        QtyPerUOM := 24; // CASE = 24 PCS
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+
+        // [GIVEN] Three tracking reservation entries that would produce rounding issues when summed
+        // Using values that end in x.xxxx7 when divided by 24:
+        // 220 / 24 = 9.16666666... rounds to approximately 9.16667
+        // 55 / 24 = 2.29166666... rounds to approximately 2.29167
+        // 13 / 24 = 0.54166666... rounds to approximately 0.54167
+        // Sum = 12.00001 (incorrect) vs 12 (correct with 288 base qty total)
+        BaseQty1 := -220; // First tracking entry base quantity
+        BaseQty2 := -55;  // Second tracking entry base quantity
+        BaseQty3 := -13;  // Third tracking entry base quantity (288 - 220 - 55 = 13)
+
+        SourceID := LibraryUtility.GenerateGUID();
+        SourceRefNo := LibraryRandom.RandInt(1000);
+
+        // Create reservation entries with Tracking status simulating order tracking split
+        CreateTrackingReservationEntry(
+            ReservEntry1, Item."No.", BaseQty1, QtyPerUOM,
+            SourceID, SourceRefNo);
+
+        CreateTrackingReservationEntry(
+            ReservEntry2, Item."No.", BaseQty2, QtyPerUOM,
+            SourceID, SourceRefNo);
+
+        CreateTrackingReservationEntry(
+            ReservEntry3, Item."No.", BaseQty3, QtyPerUOM,
+            SourceID, SourceRefNo);
+
+        // [WHEN] We sum the Quantity fields from all tracking entries
+        ReservEntry1.Find();
+        ReservEntry2.Find();
+        ReservEntry3.Find();
+
+        TotalQuantity := ReservEntry1.Quantity + ReservEntry2.Quantity + ReservEntry3.Quantity;
+
+        // [THEN] The total quantity should equal the correctly rounded sum
+        // Total base quantity = 220 + 55 + 13 = 288
+        // Expected quantity in non-base UOM = 288 / 24 = 12 exactly
+        ExpectedQty := -12; // Negative because these are demand entries
+
+        Assert.AreEqual(ExpectedQty, TotalQuantity,
+            'Total Quantity should be correctly calculated without rounding errors when tracking entries are included in CalcReservationQuantity');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ValidateQtyBaseRecalcsQtyWithTrackingEntries()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ReservEntry: Record "Reservation Entry";
+        ExistingReservEntry: Record "Reservation Entry";
+        UnitOfMeasure: Record "Unit of Measure";
+        QtyPerUOM: Decimal;
+        SourceID: Code[20];
+        SourceRefNo: Integer;
+    begin
+        // [FEATURE] [Order Tracking] [UOM]
+        // [SCENARIO] When validating Quantity (Base) on a reservation entry with Tracking status,
+        // the Quantity field should be correctly calculated considering other tracking entries.
+
+        // [GIVEN] An item with a non-base UOM
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+
+        QtyPerUOM := 24;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+
+        SourceID := LibraryUtility.GenerateGUID();
+        SourceRefNo := LibraryRandom.RandInt(1000);
+
+        // [GIVEN] An existing tracking reservation entry
+        CreateTrackingReservationEntry(
+            ExistingReservEntry, Item."No.", -220, QtyPerUOM,
+            SourceID, SourceRefNo);
+
+        // [WHEN] Creating a new tracking entry and validating Quantity (Base)
+        CreateTrackingReservationEntry(
+            ReservEntry, Item."No.", -68, QtyPerUOM,
+            SourceID, SourceRefNo);
+
+        // [THEN] The calculated quantities should be consistent
+        // Existing entry: -220 base / 24 = -9.16667 (rounded)
+        // New entry: -68 base / 24 = -2.83333 (rounded)
+        // But together: -288 base / 24 = -12 exactly
+        // So new entry quantity should account for the difference to make total = -12
+        ExistingReservEntry.Find();
+        ReservEntry.Find();
+
+        Assert.AreEqual(-12, ExistingReservEntry.Quantity + ReservEntry.Quantity,
+            'Combined Quantity of tracking entries should sum to correct total');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Reserv. Entry Qty Rounding");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Reserv. Entry Qty Rounding");
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Reserv. Entry Qty Rounding");
+    end;
+
+    local procedure CreateTrackingReservationEntry(var ReservEntry: Record "Reservation Entry"; ItemNo: Code[20]; QtyBase: Decimal; QtyPerUOM: Decimal; SourceID: Code[20]; SourceRefNo: Integer)
+    begin
+        ReservEntry.Init();
+        ReservEntry."Entry No." := LibraryUtility.GetNewRecNo(ReservEntry, ReservEntry.FieldNo("Entry No."));
+        ReservEntry."Item No." := ItemNo;
+        ReservEntry."Reservation Status" := ReservEntry."Reservation Status"::Tracking;
+        ReservEntry."Source Type" := Database::"Sales Line";
+        ReservEntry."Source Subtype" := 1; // Order
+        ReservEntry."Source ID" := SourceID;
+        ReservEntry."Source Ref. No." := SourceRefNo;
+        ReservEntry.Positive := QtyBase > 0;
+        ReservEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservEntry.Validate("Quantity (Base)", QtyBase);
+        ReservEntry.Insert();
+    end;
+}

