diff --git a/App/Layers/W1/Tests/SCM/SCMWarehousePickPlaceLineUpdate.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMWarehousePickPlaceLineUpdate.Codeunit.al
new file mode 100644
index 00000000..60282a4b
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMWarehousePickPlaceLineUpdate.Codeunit.al
@@ -0,0 +1,195 @@
+codeunit 137098 "SCM Whse Pick Place Line Upd"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Pick] [SCM]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    procedure ChangeQtyOnLastTakeLineUpdatesCorrespondingPlaceLine()
+    var
+        Location: Record Location;
+        Bin: array[6] of Record Bin;
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseEmployee: Record "Warehouse Employee";
+        TakeLineNo: array[5] of Integer;
+        PlaceLineNo: array[5] of Integer;
+        OriginalPlaceQty: array[5] of Decimal;
+        BinQty: Decimal;
+        NewQty: Decimal;
+        TotalQty: Decimal;
+        i: Integer;
+    begin
+        // [SCENARIO] When changing quantity on the last Take line in a Warehouse Pick for Production Consumption,
+        // the corresponding last Place line should be updated, not the first Place line.
+        
+        // [GIVEN] Create a Location with Require Pick and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        Location.Validate("Prod. Consump. Whse. Handling", Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        // [GIVEN] Create bins for inventory and production
+        for i := 1 to 5 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, 'S-01-0' + Format(i), '', '');
+        LibraryWarehouse.CreateBin(Bin[6], Location.Code, 'TO-PROD', '', '');
+        Location.Validate("To-Production Bin Code", Bin[6].Code);
+        Location.Modify(true);
+
+        // [GIVEN] Create Warehouse Employee
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Create Component Item with Allow Whse. Overpick = true and Flushing Method = Pick + Manual
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Flushing Method", ComponentItem."Flushing Method"::"Pick + Manual");
+        ComponentItem.Validate("Allow Whse. Overpick", true);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Create inventory for the component item in 5 different bins (900 qty each = 4500 total)
+        BinQty := 900;
+        TotalQty := 0;
+        for i := 1 to 5 do begin
+            CreateAndPostItemJournalLine(ComponentItem."No.", BinQty, Bin[i].Code, Location.Code);
+            TotalQty := TotalQty + BinQty;
+        end;
+
+        // [GIVEN] Create Parent Item with Production BOM containing the Component Item
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine,
+            '',
+            ProductionBOMLine.Type::Item,
+            ComponentItem."No.",
+            1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create and Refresh Released Production Order for 4200 qty
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder,
+            ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item,
+            ParentItem."No.",
+            4200);
+        ProductionOrder.Validate("Location Code", Location.Code);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Update Prod. Order Component with Location Code and Bin Code
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.Validate("Location Code", Location.Code);
+        ProdOrderComponent.Validate("Bin Code", Bin[6].Code);
+        ProdOrderComponent.Modify(true);
+
+        // [GIVEN] Create Warehouse Pick from Production Order
+        ProductionOrder.CreatePick(UserId, 0, false, false, false);
+
+        // [GIVEN] Get the Warehouse Activity Header
+        WarehouseActivityLine.SetRange("Source Document", WarehouseActivityLine."Source Document"::"Prod. Consumption");
+        WarehouseActivityLine.SetRange("Source No.", ProductionOrder."No.");
+        WarehouseActivityLine.SetRange("Item No.", ComponentItem."No.");
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityHeader.Get(WarehouseActivityHeader.Type::Pick, WarehouseActivityLine."No.");
+
+        // [GIVEN] Collect the line numbers and quantities of Take and Place lines
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityHeader.Type);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.SetCurrentKey("Line No.");
+        i := 0;
+        if WarehouseActivityLine.FindSet() then
+            repeat
+                i := i + 1;
+                TakeLineNo[i] := WarehouseActivityLine."Line No.";
+            until WarehouseActivityLine.Next() = 0;
+
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        i := 0;
+        if WarehouseActivityLine.FindSet() then
+            repeat
+                i := i + 1;
+                PlaceLineNo[i] := WarehouseActivityLine."Line No.";
+                OriginalPlaceQty[i] := WarehouseActivityLine.Quantity;
+            until WarehouseActivityLine.Next() = 0;
+
+        // [WHEN] Change the quantity on the LAST Take line from 900 to 400
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.FindLast();
+        NewQty := 400;
+        WarehouseActivityLine.Validate(Quantity, NewQty);
+        WarehouseActivityLine.Modify(true);
+
+        // [THEN] The LAST Place line should have its quantity updated to match
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.FindLast();
+        Assert.AreEqual(
+            NewQty,
+            WarehouseActivityLine.Quantity,
+            'Last Place line quantity should be updated to match the Last Take line quantity.');
+
+        // [THEN] The second Place line should NOT have been changed (it should retain original quantity)
+        WarehouseActivityLine.Get(WarehouseActivityHeader.Type, WarehouseActivityHeader."No.", PlaceLineNo[2]);
+        Assert.AreEqual(
+            OriginalPlaceQty[2],
+            WarehouseActivityLine.Quantity,
+            'Second Place line quantity should NOT be changed when modifying the Last Take line.');
+
+        // Cleanup
+        WarehouseEmployee.Delete();
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; Qty: Decimal; BinCode: Code[20]; LocationCode: Code[10])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine,
+            ItemJournalTemplate.Name,
+            ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.",
+            ItemNo,
+            Qty);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    [MessageHandler]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Empty handler to suppress message dialogs
+    end;
+}

