+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyOrderId()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        CopyDocMgt: Codeunit "Copy Document Mgt.";
+        PostedInvoiceNo: Code[20];
+        OrderId: BigInteger;
+        OrderNo: Code[50];
+        RefundId: BigInteger;
+    begin
+        // [SCENARIO] Copy Document from Posted Invoice clears Shopify Order Id, Order No, and Refund Id
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No, and Refund Id populated
+        Initialize();
+        OrderId := Any.IntegerInRange(10000, 99999);
+        OrderNo := CopyStr(Any.AlphanumericText(20), 1, 50);
+        RefundId := Any.IntegerInRange(10000, 99999);
+        CreateItem(Item, Any.IntegerInRange(100, 1000));
+        LibrarySales.CreateCustomer(Customer);
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithShopifyFields(Item, Customer, 1, OrderId, OrderNo, RefundId);
+
+        // [GIVEN] A new Sales Header to copy to
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+
+        // [WHEN] Copy Document is invoked to copy the posted invoice
+        CopyDocMgt.SetProperties(true, false, false, false, true, true, true);
+        CopyDocMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, SalesHeader);
+
+        // [THEN] Shopify Order Id should be cleared
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared after copy');
+
+        // [THEN] Shopify Order No should be cleared
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared after copy');
+
+        // [THEN] Shopify Refund Id should be cleared
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared after copy');
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        IsInitialized := true;
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyFields(Item: Record Item; Customer: Record Customer; NumberOfLines: Integer; OrderId: BigInteger; OrderNo: Code[50]; RefundId: BigInteger): Code[20]
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader."Shpfy Order Id" := OrderId;
+        SalesHeader."Shpfy Order No." := OrderNo;
+        SalesHeader."Shpfy Refund Id" := RefundId;
+        SalesHeader.Modify();
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", NumberOfLines);
+        exit(LibrarySales.PostSalesDocument(SalesHeader, true, true));
+    end;
+
+    local procedure CreateItem(var Item: Record Item; Amount: Decimal)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", Amount);
+        Item.Validate("Last Direct Cost", Amount);
+        Item.Modify(true);
+    end;
+}

