+codeunit 138900 "Bill-to Contact Info Update"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Sales] [Invoice] [Bill-to Customer] [Contact]
+    end;
+
+    var
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes,CustomerListModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure BillToContactInfoUpdatesOnCustomerLookup()
+    var
+        SellToCustomer: Record Customer;
+        BillToCustomer: Record Customer;
+        SellToContact: Record Contact;
+        BillToContact: Record Contact;
+        SalesHeader: Record "Sales Header";
+        SalesInvoice: TestPage "Sales Invoice";
+        ExpectedPhoneNo: Text[30];
+        ExpectedMobilePhoneNo: Text[30];
+        ExpectedEmail: Text[80];
+    begin
+        // [SCENARIO] When selecting another customer via the Bill-to Name lookup, 
+        // the Bill-to contact phone number, mobile phone number, and email should update accordingly.
+        Initialize();
+
+        // [GIVEN] Customer "A" (Sell-to Customer) with a contact having specific phone/email
+        CreateCustomerWithContact(SellToCustomer, SellToContact);
+        SetContactInfo(SellToContact, '111-1111', '222-2222', 'contact1@test.com');
+
+        // [GIVEN] Customer "B" (Bill-to Customer) with a different contact having different phone/email
+        CreateCustomerWithContact(BillToCustomer, BillToContact);
+        ExpectedPhoneNo := '333-3333';
+        ExpectedMobilePhoneNo := '444-4444';
+        ExpectedEmail := 'contact2@test.com';
+        SetContactInfo(BillToContact, ExpectedPhoneNo, ExpectedMobilePhoneNo, ExpectedEmail);
+
+        // [GIVEN] A Sales Invoice created for Customer "A"
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, SellToCustomer."No.");
+
+        // Enqueue the Bill-to Customer No. for the modal page handler to select
+        LibraryVariableStorage.Enqueue(BillToCustomer."No.");
+
+        // [WHEN] Open the Sales Invoice and use the lookup on "Bill-to Name" to select Customer "B"
+        SalesInvoice.OpenEdit();
+        SalesInvoice.GotoRecord(SalesHeader);
+
+        // Change Bill-to option to "Another Customer" to make Bill-to Name editable
+        SalesInvoice.BillToOptions.SetValue(Format("Sales Bill-to Options"::"Another Customer"));
+
+        // Trigger the lookup on Bill-to Name field - this invokes the fix
+        SalesInvoice."Bill-to Name".Lookup();
+
+        // [THEN] The Bill-to contact phone, mobile phone, and email fields should show the new customer's contact info
+        SalesInvoice.BillToContactPhoneNo.AssertEquals(ExpectedPhoneNo);
+        SalesInvoice.BillToContactMobilePhoneNo.AssertEquals(ExpectedMobilePhoneNo);
+        SalesInvoice.BillToContactEmail.AssertEquals(ExpectedEmail);
+
+        SalesInvoice.Close();
+
+        // Teardown
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        SalesHeader: Record "Sales Header";
+        LibraryApplicationArea: Codeunit "Library - Application Area";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Bill-to Contact Info Update");
+        LibraryVariableStorage.Clear();
+        SalesHeader.DontNotifyCurrentUserAgain(SalesHeader.GetModifyBillToCustomerAddressNotificationId());
+        SalesHeader.DontNotifyCurrentUserAgain(SalesHeader.GetModifyCustomerAddressNotificationId());
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Bill-to Contact Info Update");
+
+        LibraryApplicationArea.EnableFoundationSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Bill-to Contact Info Update");
+    end;
+
+    local procedure CreateCustomerWithContact(var Customer: Record Customer; var Contact: Record Contact)
+    var
+        ContactBusinessRelation: Record "Contact Business Relation";
+    begin
+        LibraryMarketing.CreateCompanyContact(Contact);
+        LibrarySales.CreateCustomer(Customer);
+        LibraryMarketing.CreateBusinessRelationBetweenContactAndCustomer(ContactBusinessRelation, Contact."No.", Customer."No.");
+
+        // Update customer's primary contact to the created contact
+        Customer.Validate("Primary Contact No.", Contact."No.");
+        Customer.Modify(true);
+    end;
+
+    local procedure SetContactInfo(var Contact: Record Contact; PhoneNo: Text[30]; MobilePhoneNo: Text[30]; Email: Text[80])
+    begin
+        Contact.Validate("Phone No.", PhoneNo);
+        Contact.Validate("Mobile Phone No.", MobilePhoneNo);
+        Contact.Validate("E-Mail", Email);
+        Contact.Modify(true);
+    end;
+
+    [ConfirmHandler]
+    [Scope('OnPrem')]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure CustomerListModalPageHandler(var CustomerList: TestPage "Customer List")
+    var
+        CustomerNo: Code[20];
+    begin
+        CustomerNo := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(CustomerNo));
+        CustomerList.Filter.SetFilter("No.", CustomerNo);
+        CustomerList.First();
+        CustomerList.OK().Invoke();
+    end;
+}

