@@ -0,0 +1,154 @@
+codeunit 135302 "Item Charge Default QtyToShip"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item Charge] [Sales Return Order] [Default Quantity to Ship]
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+        OptionString: Option PostedReturnReceipt,PostedInvoices,PostedShipments,PostedCrMemo;
+
+    [Test]
+    [HandlerFunctions('ItemChargeAssignmentSalesPageHandler,PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure GetPostedDocLinesToReverseWithItemChargeAndDefaultQtyToShipBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        SalesHeader: Record "Sales Header";
+        SalesHeaderReturnOrder: Record "Sales Header";
+        SalesLineItem: Record "Sales Line";
+        SalesLineCharge: Record "Sales Line";
+        ItemNo: Code[20];
+        ItemChargeNo: Code[20];
+        Quantity: Decimal;
+    begin
+        // [FEATURE] [Item Charge] [Sales Return Order] [Default Quantity to Ship]
+        // [SCENARIO] Item Charge should be successfully retrieved into Sales Return Order
+        // via "Get Posted Document Lines to Reverse" when "Default Quantity to Ship" is set to Blank
+        Initialize();
+
+        // [GIVEN] Set "Default Quantity to Ship" to Blank on Sales & Receivables Setup
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Default Quantity to Ship" := SalesReceivablesSetup."Default Quantity to Ship"::Blank;
+        SalesReceivablesSetup.Modify(true);
+
+        // [GIVEN] Create an Item and Item Charge
+        ItemNo := LibraryInventory.CreateItemNo();
+        ItemChargeNo := LibraryInventory.CreateItemChargeNo();
+        Quantity := LibraryRandom.RandIntInRange(5, 25);
+
+        // [GIVEN] Create Sales Order with Item line and Item Charge line
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLineItem, SalesHeader, SalesLineItem.Type::Item, ItemNo, Quantity);
+        SalesLineItem.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineItem.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLineCharge, SalesHeader, SalesLineCharge.Type::"Charge (Item)", ItemChargeNo, Quantity);
+        SalesLineCharge.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineCharge.Modify(true);
+
+        // [GIVEN] Assign Item Charge to Item Line
+        LibraryVariableStorage.Enqueue(Quantity);
+        SalesLineCharge.ShowItemChargeAssgnt();
+
+        // [GIVEN] Post Sales Order (Ship and Invoice)
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] Create Sales Return Order for the same customer
+        LibrarySales.CreateSalesHeader(
+            SalesHeaderReturnOrder,
+            SalesHeaderReturnOrder."Document Type"::"Return Order",
+            SalesHeader."Sell-to Customer No.");
+
+        // [WHEN] Run "Get Posted Document Lines to Reverse" for posted invoice
+        LibraryVariableStorage.Enqueue(OptionString::PostedInvoices);
+        SalesHeaderReturnOrder.GetPstdDocLinesToReverse();
+
+        // [THEN] Sales Return Order lines are created for both Item and Item Charge without error
+        VerifySalesReturnOrderLinesExist(SalesHeaderReturnOrder, ItemNo, ItemChargeNo);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Charge Default QtyToShip");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Charge Default QtyToShip");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        LibrarySetupStorage.Save(DATABASE::"Sales & Receivables Setup");
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Charge Default QtyToShip");
+    end;
+
+    local procedure VerifySalesReturnOrderLinesExist(SalesHeader: Record "Sales Header"; ItemNo: Code[20]; ItemChargeNo: Code[20])
+    var
+        SalesLine: Record "Sales Line";
+        ItemLineFound: Boolean;
+        ItemChargeLineFound: Boolean;
+    begin
+        SalesLine.SetRange("Document Type", SalesHeader."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeader."No.");
+        SalesLine.FindSet();
+        repeat
+            if (SalesLine.Type = SalesLine.Type::Item) and (SalesLine."No." = ItemNo) then
+                ItemLineFound := true;
+            if (SalesLine.Type = SalesLine.Type::"Charge (Item)") and (SalesLine."No." = ItemChargeNo) then
+                ItemChargeLineFound := true;
+        until SalesLine.Next() = 0;
+
+        Assert.IsTrue(ItemLineFound, 'Item line not found in Sales Return Order');
+        Assert.IsTrue(ItemChargeLineFound, 'Item Charge line not found in Sales Return Order');
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemChargeAssignmentSalesPageHandler(var ItemChargeAssignmentSales: TestPage "Item Charge Assignment (Sales)")
+    begin
+        ItemChargeAssignmentSales."Qty. to Assign".SetValue(LibraryVariableStorage.DequeueDecimal());
+        ItemChargeAssignmentSales.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    var
+        DocumentType: Option "Posted Shipments","Posted Invoices","Posted Return Receipts","Posted Cr. Memos";
+    begin
+        case LibraryVariableStorage.DequeueInteger() of
+            OptionString::PostedReturnReceipt:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Return Receipts"));
+            OptionString::PostedInvoices:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Invoices"));
+            OptionString::PostedShipments:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Shipments"));
+            OptionString::PostedCrMemo:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Cr. Memos"));
+        end;
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
+}

