+        GLAccount.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GLAccount.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GLAccount.Validate("Gen. Posting Type", GLAccount."Gen. Posting Type"::Purchase);
+        GeneralPostingSetup.SetFilter("Purch. Account", '<>%1', '');
+        if GeneralPostingSetup.FindFirst() then
+            GLAccount.Validate("Gen. Prod. Posting Group", GeneralPostingSetup."Gen. Prod. Posting Group");
+        GLAccount.Modify(true);
+
+        // [GIVEN] Create Vendor with VAT Bus. Posting Group and "Prices Including VAT" = true
+        LibraryPurchase.CreateVendor(Vendor);
+        Vendor.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        Vendor.Validate("Prices Including VAT", true);
+        Vendor.Modify(true);
+
+        // [GIVEN] Create Purchase Invoice with the vendor
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Invoice, Vendor."No.");
+
+        // [GIVEN] Create Purchase Line with G/L Account, Quantity = 1, Direct Unit Cost Incl VAT = 14.19
+        // This specific amount causes rounding issues with 100% Non-Deductible VAT and Prices Including VAT
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::"G/L Account", GLAccount."No.", 1);
+        PurchaseLine.Validate("Direct Unit Cost", 14.19);
+        PurchaseLine.Modify(true);
+
+        // [WHEN] Post purchase document
+        DocNo := LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, true);
+
+        // [THEN] VAT Entry is posted successfully (no inconsistency error)
+        FindVATEntry(VATEntry, DocNo);
+        Assert.RecordCount(VATEntry, 1);
+
+        // [THEN] VAT Entry has Base = 0 and Amount = 0 because Non-Deductible VAT is 100%
+        Assert.AreEqual(0, VATEntry.Base, 'VAT Entry Base should be 0 for 100% Non-Deductible VAT');
+        Assert.AreEqual(0, VATEntry.Amount, 'VAT Entry Amount should be 0 for 100% Non-Deductible VAT');
+    end;
+
