     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

diff --git a/App/Layers/W1/Tests/SCM/SCMWhsePutawayBreakbulk.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMWhsePutawayBreakbulk.Codeunit.al
