@@ -0,0 +1,250 @@
+codeunit 137999 "SCM Whse. Putaway Breakbulk"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandler')]
+    [Scope('OnPrem')]
+    procedure RegisterPutAwayWithBreakbulkFilterRegistersAllLines()
+    var
+        Location: Record Location;
+        ReceiveBin: Record Bin;
+        PutawayBin1: Record Bin;
+        PutawayBin2: Record Bin;
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        WarehouseReceiptHeader: Record "Warehouse Receipt Header";
+        WarehouseReceiptLine: Record "Warehouse Receipt Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        RegisteredWhseActivityLine: Record "Registered Whse. Activity Line";
+        WarehousePutaway: TestPage "Warehouse Put-away";
+        QtyPerUOM: Decimal;
+        PurchaseQty: Decimal;
+        TotalLinesBeforeRegister: Integer;
+        RegisteredLinesCount: Integer;
+    begin
+        // [FEATURE] [Warehouse Put-away] [Breakbulk Filter]
+        // [SCENARIO] When registering a warehouse put-away with breakbulk filter set to Yes, all put-away lines should be registered (not just filtered lines)
+
+        // [GIVEN] A location with Directed Put-away and Pick enabled with Allow Breakbulk
+        Initialize();
+        CreateFullWMSLocationWithBreakbulk(Location, ReceiveBin, PutawayBin1, PutawayBin2);
+
+        // [GIVEN] An item with Base Unit of Measure = PCS and an additional UOM = BOX with Qty. per UOM > 1
+        QtyPerUOM := LibraryRandom.RandIntInRange(10, 20);
+        CreateItemWithPutawayUOM(Item, ItemUnitOfMeasure, QtyPerUOM);
+
+        // [GIVEN] A released Purchase Order with BOX as UOM (the larger unit)
+        PurchaseQty := LibraryRandom.RandIntInRange(2, 5);
+        CreateAndReleasePurchaseOrderWithUOM(PurchaseHeader, PurchaseLine, Item."No.", Location.Code, PurchaseQty, ItemUnitOfMeasure.Code);
+
+        // [GIVEN] A Warehouse Receipt created and posted from the Purchase Order
+        LibraryWarehouse.CreateWhseReceiptFromPO(PurchaseHeader);
+        FindWarehouseReceiptLine(WarehouseReceiptLine, PurchaseHeader."No.", Location.Code);
+        WarehouseReceiptHeader.Get(WarehouseReceiptLine."No.");
+        LibraryWarehouse.PostWhseReceipt(WarehouseReceiptHeader);
+
+        // [GIVEN] The put-away was created with breakbulk lines (due to different Put-away UOM)
+        FindWarehouseActivityHeader(WarehouseActivityHeader, WarehouseActivityLine."Activity Type"::"Put-away", PurchaseHeader."No.");
+
+        // [GIVEN] Count all put-away lines before registration
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        TotalLinesBeforeRegister := WarehouseActivityLine.Count();
+
+        // [GIVEN] The put-away has breakbulk lines (more than 2 lines indicates breakbulk)
+        Assert.IsTrue(TotalLinesBeforeRegister > 2, 'Put-away should have breakbulk lines (more than 2 lines)');
+
+        // [GIVEN] The Breakbulk Filter is set to Yes on the put-away header
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Opening the Warehouse Put-away page and registering the put-away
+        WarehousePutaway.OpenEdit();
+        WarehousePutaway.GoToRecord(WarehouseActivityHeader);
+        WarehousePutaway."Autofill Qty. to Handle".Invoke();
+        WarehousePutaway."&Register Put-away".Invoke();
+        WarehousePutaway.Close();
+
+        // [THEN] All warehouse activity lines should be registered
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        RegisteredLinesCount := RegisteredWhseActivityLine.Count();
+
+        // [THEN] The number of registered lines should match the total lines before registration
+        Assert.AreEqual(TotalLinesBeforeRegister, RegisteredLinesCount,
+            'All put-away lines should be registered when breakbulk filter is set to Yes');
+
+        // [THEN] The original put-away should be deleted (fully registered)
+        Assert.IsFalse(WarehouseActivityHeader.Get(WarehouseActivityHeader.Type, WarehouseActivityHeader."No."),
+            'Put-away should be fully registered and deleted');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        WarehouseEmployee: Record "Warehouse Employee";
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Whse. Putaway Breakbulk");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Whse. Putaway Breakbulk");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        WarehouseEmployee.DeleteAll(true);
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+        LibrarySales.SetOrderNoSeriesInSetup();
+        LibraryPurchase.SetOrderNoSeriesInSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Whse. Putaway Breakbulk");
+    end;
+
+    local procedure CreateFullWMSLocationWithBreakbulk(var Location: Record Location; var ReceiveBin: Record Bin; var PutawayBin1: Record Bin; var PutawayBin2: Record Bin)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        PutAwayTemplateHeader: Record "Put-away Template Header";
+        PutAwayTemplateLine: Record "Put-away Template Line";
+        AdjustmentBin: Record Bin;
+        Zone: Record Zone;
+    begin
+        Clear(Location);
+        Location.Init();
+
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location."Bin Mandatory" := true;
+        Location.Validate("Directed Put-away and Pick", true);
+        if Location."Require Pick" then
+            if Location."Require Shipment" then begin
+                Location."Prod. Consump. Whse. Handling" := Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)";
+                Location."Asm. Consump. Whse. Handling" := Location."Asm. Consump. Whse. Handling"::"Warehouse Pick (mandatory)";
+                Location."Job Consump. Whse. Handling" := Location."Job Consump. Whse. Handling"::"Warehouse Pick (mandatory)";
+            end else begin
+                Location."Prod. Consump. Whse. Handling" := Location."Prod. Consump. Whse. Handling"::"Inventory Pick/Movement";
+                Location."Asm. Consump. Whse. Handling" := Location."Asm. Consump. Whse. Handling"::"Inventory Movement";
+                Location."Job Consump. Whse. Handling" := Location."Job Consump. Whse. Handling"::"Inventory Pick";
+            end
+        else begin
+            Location."Prod. Consump. Whse. Handling" := Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (optional)";
+            Location."Asm. Consump. Whse. Handling" := Location."Asm. Consump. Whse. Handling"::"Warehouse Pick (optional)";
+            Location."Job Consump. Whse. Handling" := Location."Job Consump. Whse. Handling"::"Warehouse Pick (optional)";
+        end;
+
+        if Location."Require Put-away" and not Location."Require Receive" then
+            Location."Prod. Output Whse. Handling" := Location."Prod. Output Whse. Handling"::"Inventory Put-away";
+        Location.Modify(true);
+
+        // Create Adjustment Zone and Bin - required for Directed Put-away and Pick
+        LibraryWarehouse.CreateZone(Zone, 'ADJUST', Location.Code, LibraryWarehouse.SelectBinType(false, false, false, false), '', '', 0, false);
+        LibraryWarehouse.CreateBin(AdjustmentBin, Location.Code, 'ADJBIN', Zone.Code, LibraryWarehouse.SelectBinType(false, false, false, false));
+        Location.Validate("Adjustment Bin Code", AdjustmentBin.Code);
+        Location.Modify(true);
+
+        // Create Pick zone
+        LibraryWarehouse.CreateZone(Zone, 'PICK', Location.Code, LibraryWarehouse.SelectBinType(false, false, true, true), '', '', 100, false);
+        LibraryWarehouse.CreateBin(PutawayBin1, Location.Code, 'Bin1', Zone.Code, LibraryWarehouse.SelectBinType(false, false, true, true));
+        PutawayBin1.Validate("Bin Ranking", 100);
+        PutawayBin1.Modify(true);
+        LibraryWarehouse.CreateBin(PutawayBin2, Location.Code, 'Bin2', Zone.Code, LibraryWarehouse.SelectBinType(false, false, true, true));
+        PutawayBin2.Validate("Bin Ranking", 200);
+        PutawayBin2.Modify(true);
+
+        // Receive Zone
+        LibraryWarehouse.CreateZone(Zone, 'RECEIVE', Location.Code, LibraryWarehouse.SelectBinType(true, false, false, false), '', '', 10, false);
+        LibraryWarehouse.CreateBin(ReceiveBin, Location.Code, 'Bin3', Zone.Code, LibraryWarehouse.SelectBinType(true, false, false, false));
+        Location.Validate("Receipt Bin Code", ReceiveBin.Code);
+
+        // Create the put-away template
+        LibraryWarehouse.CreatePutAwayTemplateHeader(PutAwayTemplateHeader);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, true, false, true, true, true, false);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, true, false, true, true, false, false);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, false, true, true, true, false, false);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, false, true, true, false, false, false);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, false, true, false, false, false, true);
+        LibraryWarehouse.CreatePutAwayTemplateLine(PutAwayTemplateHeader, PutAwayTemplateLine, false, true, false, false, false, false);
+        Location.Validate("Put-away Template Code", PutAwayTemplateHeader.Code);
+
+        // Enable breakbulk
+        Location.Validate("Allow Breakbulk", true);
+        Location.Modify(true);
+
+        // Create warehouse employee
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+
+    local procedure CreateItemWithPutawayUOM(var Item: Record Item; var ItemUnitOfMeasure: Record "Item Unit of Measure"; QtyPerUOM: Decimal)
+    var
+        UnitOfMeasure: Record "Unit of Measure";
+    begin
+        LibraryInventory.CreateItem(Item);
+
+        // Create a larger unit of measure (e.g., BOX)
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+
+        // Set the Put-away Unit of Measure to the base unit (PCS) - this causes breakbulk when receiving in BOX
+        Item.Validate("Put-away Unit of Measure Code", Item."Base Unit of Measure");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndReleasePurchaseOrderWithUOM(var PurchaseHeader: Record "Purchase Header"; var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; UOMCode: Code[10])
+    begin
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, '');
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, ItemNo, Quantity);
+        PurchaseLine.Validate("Location Code", LocationCode);
+        PurchaseLine.Validate("Unit of Measure Code", UOMCode);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.ReleasePurchaseDocument(PurchaseHeader);
+    end;
+
+    local procedure FindWarehouseReceiptLine(var WarehouseReceiptLine: Record "Warehouse Receipt Line"; SourceNo: Code[20]; LocationCode: Code[10])
+    begin
+        WarehouseReceiptLine.SetRange("Source Document", WarehouseReceiptLine."Source Document"::"Purchase Order");
+        WarehouseReceiptLine.SetRange("Source No.", SourceNo);
+        WarehouseReceiptLine.SetRange("Location Code", LocationCode);
+        WarehouseReceiptLine.FindFirst();
+    end;
+
+    local procedure FindWarehouseActivityHeader(var WarehouseActivityHeader: Record "Warehouse Activity Header"; ActivityType: Enum "Warehouse Activity Type"; SourceNo: Code[20])
+    var
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+    begin
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.SetRange("Source Document", WarehouseActivityLine."Source Document"::"Purchase Order");
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandler(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

