+
+    [Test]
+    [HandlerFunctions('PurchaseStatisticsChangeVATAmountModalPageHandler')]
+    procedure PostPurchInvWithFCYAndVATDiffAndNDVAT100Pct()
+    var
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        VATPostingSetup: Record "VAT Posting Setup";
+        GeneralPostingSetup: Record "General Posting Setup";
+        Currency: Record Currency;
+        PurchaseInvoicePage: TestPage "Purchase Invoice";
+        CurrencyCode: Code[10];
+        DocNo: Code[20];
+        MaxVATDifference: Decimal;
+        VATAmount: Decimal;
+        NonDeductibleVATAmount: Decimal;
+    begin
+        // [FEATURE] [FCY] [VAT Difference] [100% Non-Deductible VAT]
+        // [SCENARIO] Stan can post Purchase Invoice with FCY, Non-Deductible VAT 100% and changed VAT Amount in Statistics
+
+        Initialize();
+        MaxVATDifference := LibraryRandom.RandDecInDecimalRange(0.1, 1, 2);
+
+        // [GIVEN] "Allow VAT Difference" is enabled in Purchases Setup
+        SetAllowVATDifference(MaxVATDifference);
+
+        // [GIVEN] Normal VAT Posting Setup with "VAT %" = 20 and Non-Deductible VAT %" = 100
+        LibraryERM.CreateVATPostingSetupWithAccounts(VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Normal VAT", LibraryRandom.RandIntInRange(10, 25));
+        LibraryNonDeductibleVAT.SetAllowNonDeductibleVATForVATPostingSetup(VATPostingSetup);
+        VATPostingSetup.Validate("Non-Deductible VAT %", 100);
+        VATPostingSetup.Modify(true);
+
+        // [GIVEN] Currency EUR with "Max. VAT Difference Allowed" set
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), 10, 10);
+        Currency.Get(CurrencyCode);
+        Currency.Validate("Max. VAT Difference Allowed", MaxVATDifference);
+        Currency.Modify(true);
+
+        // [GIVEN] Purchase invoice with Currency Code = EUR, amount = 1000
+        LibraryPurchase.CreatePurchHeader(
+            PurchaseHeader, PurchaseHeader."Document Type"::Invoice,
+            LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        PurchaseHeader.Validate("Currency Code", CurrencyCode);
+        PurchaseHeader.Modify(true);
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item,
+            LibraryInventory.CreateItemWithVATProdPostingGroup(VATPostingSetup."VAT Prod. Posting Group"), LibraryRandom.RandInt(100));
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDec(100, 2));
+        PurchaseLine.Modify(true);
+
+        VATAmount := PurchaseLine."Amount Including VAT" - PurchaseLine.Amount - MaxVATDifference;
+        NonDeductibleVATAmount := VATAmount;
+        LibraryVariableStorage.Enqueue(NonDeductibleVATAmount);
+        LibraryVariableStorage.Enqueue(VATAmount);
+
+        // [GIVEN] Open purchase invoice page
+        PurchaseInvoicePage.OpenEdit();
+        PurchaseInvoicePage.Filter.SetFilter("No.", PurchaseHeader."No.");
+        // [GIVEN] Open statistics of the invoice and change VAT Amount
+        PurchaseInvoicePage.Statistics.Invoke();
+        // Called in PurchaseStatisticsChangeVATAmountModalPageHandler
+        PurchaseInvoicePage.Close();
+
+        PurchaseLine.Find();
+        // [GIVEN] "VAT Difference" is set in the purchase line
+        PurchaseLine.TestField("VAT Difference", -MaxVATDifference);
+
+        // [WHEN] Post purchase invoice
+        DocNo := LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, true);
+
+        // [THEN] Invoice is successfully posted without "The transaction cannot be completed because it will cause inconsistencies in the G/L Entry table" error
+        // [THEN] G/L Entries with purchases account have total amount equal to Line Amount + Non-Deductible VAT Amount
+        GeneralPostingSetup.Get(PurchaseLine."Gen. Bus. Posting Group", PurchaseLine."Gen. Prod. Posting Group");
+        VerifyGLEntryTotalAmount(DocNo, GeneralPostingSetup."Purch. Account", PurchaseLine.Amount + PurchaseLine."Non-Deductible VAT Amount");
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure SetAllowVATDifference(MaxVATDifference: Decimal)
+    var
+        PurchasesSetup: Record "Purchases & Payables Setup";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+    begin
+        PurchasesSetup.Get();
+        PurchasesSetup.Validate("Allow VAT Difference", true);
+        PurchasesSetup.Modify(true);
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup.Validate("Max. VAT Difference Allowed", MaxVATDifference);
+        GeneralLedgerSetup.Modify(true);
+    end;
+
+    local procedure VerifyGLEntryTotalAmount(DocumentNo: Code[20]; GLAccNo: Code[20]; ExpectedAmount: Decimal)
+    var
+        GLEntry: Record "G/L Entry";
+    begin
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.SetRange("Posting Date", WorkDate());
+        GLEntry.SetRange("G/L Account No.", GLAccNo);
+        GLEntry.CalcSums(Amount);
+        GLEntry.TestField(Amount, ExpectedAmount);
+    end;
+
+    [ModalPageHandler]
+    procedure PurchaseStatisticsChangeVATAmountModalPageHandler(var PurchaseStatisticsPage: TestPage "Purchase Statistics")
+    var
+        VATAmount: Decimal;
+        NonDeductibleVATAmount: Decimal;
+    begin
+        NonDeductibleVATAmount := LibraryVariableStorage.DequeueDecimal();
+        VATAmount := LibraryVariableStorage.DequeueDecimal();
+        PurchaseStatisticsPage.SubForm."VAT Amount".SetValue(VATAmount);
+        PurchaseStatisticsPage.SubForm.NonDeductibleAmount.AssertEquals(NonDeductibleVATAmount);
+    end;
 }
