+codeunit 137900 "SCM Prod. Order Comp Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Production Order] [Component] [Rounding Precision]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        isInitialized: Boolean;
+        ReleasedProdOrderCreatedMsg: Label 'Released Prod. Order';
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerNotRoundedToZeroWhenUOMHasQtyRoundingPrecision()
+    var
+        ComponentItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QuantityPer: Decimal;
+    begin
+        // [SCENARIO] When a component's Item UOM has a 'Qty. Rounding Precision' of 1, and a Finished Good consumes partial quantity,
+        // the Prod. Order Component created from Sales Order should have correct 'Qty. Per' and 'Expected Qty.'
+        // This tests the fix that uses Item."Rounding Precision" instead of UOM."Qty. Rounding Precision" for production components
+        Initialize();
+
+        // [GIVEN] A Component Item with Base UOM "PCS" having 'Qty. Rounding Precision' = 1
+        // [GIVEN] Component Item has Replenishment System = Purchase, Rounding Precision = 0.01
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Reordering Policy", ComponentItem."Reordering Policy"::"Lot-for-Lot");
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // Set 'Qty. Rounding Precision' = 1 on the Component Item's Base UOM
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] A Finished Good Item with Replenishment System = Prod. Order, Rounding Precision = 1, Reorder Policy = Order
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Reordering Policy", FGItem."Reordering Policy"::Order);
+        FGItem.Validate("Rounding Precision", 1);
+        FGItem.Modify(true);
+
+        // [GIVEN] A Certified Production BOM that consumes Component Item with 'Quantity Per' = 0.09 (partial quantity)
+        QuantityPer := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [GIVEN] A Sales Order for FG Item with Quantity = 1
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, FGItem."No.", 1);
+
+        // [WHEN] Create Released Production Order from Sales Order
+        LibraryVariableStorage.Enqueue(ReleasedProdOrderCreatedMsg);
+        LibraryManufacturing.CreateProductionOrderFromSalesOrder(
+            SalesHeader, ProductionOrder.Status::Released, "Create Production Order Type"::ItemOrder);
+
+        // [THEN] Find the Production Order and its Component
+        ProductionOrder.SetRange("Source Type", ProductionOrder."Source Type"::Item);
+        ProductionOrder.SetRange("Source No.", FGItem."No.");
+        ProductionOrder.SetRange(Status, ProductionOrder.Status::Released);
+        ProductionOrder.FindFirst();
+
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        // [THEN] 'Quantity Per' should be 0.09, NOT 0 (rounded down due to UOM Qty. Rounding Precision)
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Quantity per",
+            'Quantity per should not be rounded to 0 by UOM Qty. Rounding Precision');
+
+        // [THEN] 'Expected Quantity' should be 0.09 (1 * 0.09), NOT 0
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should not be rounded to 0 by UOM Qty. Rounding Precision');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Prod. Order Comp Rounding");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Prod. Order Comp Rounding");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Prod. Order Comp Rounding");
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    var
+        ExpectedMsg: Variant;
+    begin
+        LibraryVariableStorage.Dequeue(ExpectedMsg);
+        Assert.IsTrue(StrPos(Message, ExpectedMsg) > 0, Message);
+    end;
+}

