+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Modify(true);
+
+        // [GIVEN] The customer's default posting group
+        CustomerPostingGroup.Get(Customer."Customer Posting Group");
+
+        // [GIVEN] An alternative customer posting group with a different Receivables Account
+        LibrarySales.CreateCustomerPostingGroup(AltCustomerPostingGroup);
+        LibrarySales.CreateAltCustomerPostingGroup(Customer."Customer Posting Group", AltCustomerPostingGroup.Code);
+
+        // [GIVEN] A Finance Charge Memo with the alternative Customer Posting Group
