+    [Test]
+    [Scope('OnPrem')]
+    procedure MultipleProdOrderLinesMfgOvhdCostCalculation()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        UnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        LineQty: Decimal;
+        ExpectedMfgOvhdCost: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Manufacturing Overhead]
+        // [SCENARIO] Manufacturing overhead is calculated correctly when production order has multiple lines
+        Initialize();
+
+        // [GIVEN] A raw material item with Unit Cost = 100
+        UnitCost := 100;
+        IndirectCostPct := 10;
+        LineQty := 10;
+
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", UnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] A finished goods item with Indirect Cost % = 10% and a Production BOM using the raw material (Qty per = 1)
+        LibraryInventory.CreateItem(FGItem);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FGItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Modify(true);
+
+        // [GIVEN] A production order with two lines, each with Qty = 10 (total 20)
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::"Firm Planned",
+            ProductionOrder."Source Type"::Item, FGItem."No.", 0);
+        ProductionOrder.Modify(true);
+
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+            FGItem."No.", '', '', LineQty);
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+            FGItem."No.", '', '', LineQty);
+
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs for all lines
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindSet();
+        repeat
+            MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+            MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+        until ProdOrderLine.Next() = 0;
+
+        // [THEN] Manufacturing overhead = 10% of total material cost (200 = 10% of 2000)
+        // Total material cost = 100 (Unit Cost) * 1 (Qty per) * 20 (total qty) = 2000
+        // Expected Mfg Overhead = 2000 * 10% = 200
+        ExpectedMfgOvhdCost := Round(ExpMatCost * IndirectCostPct / 100);
+        Assert.AreEqual(ExpectedMfgOvhdCost, ExpMfgOvhdCost,
+            'Manufacturing overhead should be calculated correctly for multiple production order lines');
+    end;
