+        Customer.Get(SalesHeader."Sell-to Customer No.");
+        Customer.Validate("IC Partner Code", ICPartnerCode);
+        Customer.Modify(true);
+
+        // [WHEN] Post the Sales Credit Memo
+        PostedDocNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // [THEN] A Posted Sales Credit Memo exists
+        SalesCrMemoHeader.Get(PostedDocNo);
+
+        // [THEN] A Handled IC Outbox Trans. record exists for the Credit Memo
+        HandledICOutboxTrans.SetRange("Document Type", HandledICOutboxTrans."Document Type"::"Credit Memo");
+        HandledICOutboxTrans.SetRange("Source Type", HandledICOutboxTrans."Source Type"::"Sales Document");
+        HandledICOutboxTrans.SetRange("Document No.", PostedDocNo);
+        HandledICOutboxTrans.SetRange("IC Partner Code", ICPartnerCode);
+        HandledICOutboxTrans.FindFirst();
+        Assert.RecordCount(HandledICOutboxTrans, 1);
+
+        // [WHEN] Navigate to document from Handled IC Outbox Transactions
+        LibraryVariableStorage.Enqueue(PostedDocNo);
+        ICNavigation.NavigateToDocument(HandledICOutboxTrans);
+
+        // [THEN] The Posted Sales Credit Memo page opens (verified by PageHandler)
+        // PageHandler verifies the correct document was opened
+    end;
+
+    local procedure Initialize()
+    var
+        ICSetup: Record "IC Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"IC Navigation Sales CrMemo");
+
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"IC Navigation Sales CrMemo");
+        if not ICSetup.Get() then begin
+            ICSetup.Init();
+            ICSetup.Insert();
+        end;
+        ICSetup."Auto. Send Transactions" := false;
