--- a/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
+++ b/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
@@ -1553,5 +1553,124 @@ codeunit 139598 "AAC Auto. Acc. Group Posting"
     begin
         Reply := false;
     end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostGenJnlLineWithCurrencyAndAmountLCYRounding()
+    var
+        GenJournalLine: Record "Gen. Journal Line";
+        GLEntry: Record "G/L Entry";
+        AutomaticAccountHeader: Record "Automatic Account Header";
+        AutomaticAccountLine: Record "Automatic Account Line";
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        Currency: Record Currency;
+        GLSetup: Record "General Ledger Setup";
+        AutoAccGroupNo: Code[10];
+        GLAccountNo1: Code[20];
+        GLAccountNo2: Code[20];
+        GLAccountNo3: Code[20];
+        BalGLAccountNo: Code[20];
+        CurrencyCode: Code[10];
+        DocumentNo: Code[20];
+        PostingDate: Date;
+        AmountFCY: Decimal;
+        TotalAmountLCY: Decimal;
+    begin
+        // [FEATURE] [Currency] [Rounding]
+        // [SCENARIO 548123] Post General Journal Line with currency and automatic account group when Amount (LCY) has rounding issues
+        // [GIVEN] Currency "EUR" with exchange rate that causes rounding (1 EUR = 10.97223 LCY)
+        Initialize();
+        GLSetup.Get();
+        PostingDate := WorkDate();
+
+        // Create currency with specific exchange rate that causes rounding issues
+        // 480 EUR * 10.97223 = 5266.6704, rounded to 5266.67
+        // 5266.67 / 2 = 2633.335, rounded to 2633.34 for each 50% line
+        // 2633.34 + 2633.34 = 5266.68 <> 5266.67 (rounding issue)
+        LibraryERM.CreateCurrency(Currency);
+        CurrencyCode := Currency.Code;
+        LibraryERM.CreateExchRate(CurrencyExchangeRate, CurrencyCode, PostingDate);
+        CurrencyExchangeRate."Exchange Rate Amount" := 1;
+        CurrencyExchangeRate."Adjustment Exch. Rate Amount" := 1;
+        CurrencyExchangeRate."Relational Exch. Rate Amount" := 10.97223;
+        CurrencyExchangeRate."Relational Adjmt Exch Rate Amt" := 10.97223;
+        CurrencyExchangeRate."Fix Exchange Rate Amount" := CurrencyExchangeRate."Fix Exchange Rate Amount"::Currency;
+        CurrencyExchangeRate.Modify(true);
+
+        // [GIVEN] Automatic Account Group "AAG" with three lines:
+        // [GIVEN] Line1: "G/L Account No." = "ACC1", "Allocation %" = 50
+        // [GIVEN] Line2: "G/L Account No." = "ACC2", "Allocation %" = 50
+        // [GIVEN] Line3: "G/L Account No." = "ACC3", "Allocation %" = -100 (balancing line)
+        LibraryAAC.CreateAutomaticAccountHeader(AutomaticAccountHeader);
+        AutoAccGroupNo := AutomaticAccountHeader."No.";
+        GLAccountNo1 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo2 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo3 := LibraryERM.CreateGLAccountNo();
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo1);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo2);
+        AutomaticAccountLine.Validate("Allocation %", 50);
+        AutomaticAccountLine.Modify(true);
+
+        LibraryAAC.CreateAutomaticAccountLine(AutomaticAccountLine, AutoAccGroupNo);
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo3);
+        AutomaticAccountLine.Validate("Allocation %", -100);
+        AutomaticAccountLine.Modify(true);
+
+        // [GIVEN] General Journal with Currency and two lines:
+        // [GIVEN] Line1: Amount = 480 EUR, "Automatic Account Group" = "AAG", "Bal. Account No." = ''
+        // [GIVEN] Line2: Amount = -480 EUR, "Automatic Account Group" = '', "Bal. Account No." = '' (balancing entry)
+        AmountFCY := 480;
+        BalGLAccountNo := LibraryERM.CreateGLAccountNo();
+
+        LibraryJournals.CreateGenJournalLineWithBatch(
+            GenJournalLine, GenJournalLine."Document Type"::" ",
+            GenJournalLine."Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(), AmountFCY);
+        GenJournalLine.Validate("Posting Date", PostingDate);
+        GenJournalLine.Validate("Bal. Account No.", '');
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate("Automatic Account Group", AutoAccGroupNo);
+        GenJournalLine.Modify(true);
+        DocumentNo := GenJournalLine."Document No.";
+        TotalAmountLCY := GenJournalLine."Amount (LCY)";
+
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name",
+            GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account", BalGLAccountNo, -AmountFCY);
+        GenJournalLine.Validate("Posting Date", PostingDate);
+        GenJournalLine.Validate("Document No.", DocumentNo);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Modify(true);
+
+        // [WHEN] Post General Journal
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] All G/L Entries for the document balance to zero (no rounding inconsistency)
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'G/L Entries must balance to zero');
+
+        // [THEN] The sum of automatic account entries (ACC1 + ACC2 + ACC3) equals zero
+        GLEntry.SetFilter("G/L Account No.", '%1|%2|%3', GLAccountNo1, GLAccountNo2, GLAccountNo3);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Automatic account entries must balance to zero');
+
+        // [THEN] Each 50% allocation line has the correctly rounded Amount (LCY)
+        GLEntry.SetRange("G/L Account No.", GLAccountNo1);
+        GLEntry.FindFirst();
+        Assert.AreEqual(Round(TotalAmountLCY * 0.5, GLSetup."Amount Rounding Precision"), GLEntry.Amount,
+            'First 50% allocation should have correctly rounded amount');
+
+        GLEntry.SetRange("G/L Account No.", GLAccountNo2);
+        GLEntry.FindFirst();
+        // The last allocation entry may have adjusted amount to ensure total balances
+        Assert.AreNearlyEqual(Round(TotalAmountLCY * 0.5, GLSetup."Amount Rounding Precision"), GLEntry.Amount,
+            GLSetup."Amount Rounding Precision", 'Second 50% allocation should have amount within rounding precision');
+    end;
 }

