+    [Test]
+    [Scope('OnPrem')]
+    procedure ProdBOMCommentsAreCopiedCorrectlyWhenSameItemHasDifferentPositions()
+    var
+        ProdItem: Record Item;
+        CompItem: Record Item;
+        UnitOfMeasure: Record "Unit of Measure";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: array[2] of Record "Production BOM Line";
+        SalesHeader: Record "Sales Header";
+        ProductionBOMCommentLine: array[2] of Record "Production BOM Comment Line";
+        ProdOrderCompCmtLine: Record "Prod. Order Comp. Cmt Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        RequisitionLine: Record "Requisition Line";
+        Position1: Code[10];
+        Position2: Code[10];
+        Comment1: Text[80];
+        Comment2: Text[80];
+    begin
+        // [SCENARIO] When the same item is listed twice on a Production BOM with different Position values,
+        // and each line has its own comment, Carry Out Action should copy the correct comment to each component.
+        Initialize();
+
+        // [GIVEN] Create Unit of Measure Code.
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+
+        // [GIVEN] Create a Component Item with purchase replenishment.
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Create Production Item with Prod. Order replenishment and Order reordering policy.
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Create Production BOM Header.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+
+        // [GIVEN] Create first Production BOM Line with the component item and Position "POS1".
+        Position1 := 'POS1';
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine[1],
+            '',
+            ProductionBOMLine[1].Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 10));
+        ProductionBOMLine[1].Validate(Position, Position1);
+        ProductionBOMLine[1].Modify(true);
+
+        // [GIVEN] Create second Production BOM Line with the SAME component item but different Position "POS2".
+        Position2 := 'POS2';
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine[2],
+            '',
+            ProductionBOMLine[2].Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 10));
+        ProductionBOMLine[2].Validate(Position, Position2);
+        ProductionBOMLine[2].Modify(true);
+
+        // [GIVEN] Create comment "Test1" for first Production BOM Line.
+        Comment1 := 'Test1';
+        CreateProductionBOMCommentLineWithText(ProductionBOMCommentLine[1], ProductionBOMLine[1], Comment1);
+
+        // [GIVEN] Create comment "Test2" for second Production BOM Line.
+        Comment2 := 'Test2';
+        CreateProductionBOMCommentLineWithText(ProductionBOMCommentLine[2], ProductionBOMLine[2], Comment2);
+
+        // [GIVEN] Update Production BOM Status to Certified.
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Validate Production BOM No. in Production Item.
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create Sales Order for the Production Item.
+        CreateSalesOrder(SalesHeader, ProdItem);
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+
+        // [GIVEN] Run Calculate Regenerative Plan.
+        RunCalculateRegenerativePlan(ProdItem."No.", '');
+
+        // [GIVEN] Accept Action Message on Requisition Line.
+        AcceptActionMessageOnReqLine(RequisitionLine, ProdItem."No.");
+
+        // [WHEN] Run Carry Out Action to create Firm Planned Prod. Order.
+        CarryOutActionPlanForFirmPlannedProdOrder(RequisitionLine);
+
+        // [THEN] Verify the Prod. Order Component with Position "POS1" has comment "Test1".
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        ProdOrderComponent.SetRange(Position, Position1);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderComponent.Status);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment1, ProdOrderCompCmtLine.Comment, 'Comment for component with Position POS1 should be Test1');
+
+        // [THEN] Verify the Prod. Order Component with Position "POS2" has comment "Test2".
+        ProdOrderComponent.SetRange(Position, Position2);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment2, ProdOrderCompCmtLine.Comment, 'Comment for component with Position POS2 should be Test2');
+    end;
