+    [Test]
+    procedure VariantCodeNotPresetForNewPriceListLine()
+    var
+        PriceListHeader: Record "Price List Header";
+        Item: Record Item;
+        ItemVariant: array[3] of Record "Item Variant";
+        SalesPriceList: TestPage "Sales Price List";
+    begin
+        // [SCENARIO] When creating a new price list line for an item with variants, the variant code from the previous line should not be preset
+        // [GIVEN] Initialize
+        Initialize(true);
+
+        // [GIVEN] Create Item with 3 variants: Blue, Red, Green
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[3], Item."No.");
+
+        // [GIVEN] Create Price List Header record
+        LibraryPriceCalculation.CreatePriceHeader(
+            PriceListHeader, PriceListHeader."Price Type"::Sale,
+            PriceListHeader."Source Type"::"All Customers", '');
+
+        // [GIVEN] Open price list page, create first line with Item and Variant[1] (e.g., "Blue")
+        SalesPriceList.OpenEdit();
+        SalesPriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item."No.");
+        SalesPriceList.Lines."Variant Code".SetValue(ItemVariant[1].Code);
+
+        // [WHEN] Create a second line with the same Item No. but without specifying a variant
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item."No.");
+
+        // [THEN] Verify Variant Code is blank (not preset from the previous line)
+        SalesPriceList.Lines."Variant Code".AssertEquals('');
+
+        // [WHEN] Verify this works for any subsequent new line as well
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Product No.".SetValue(Item."No.");
+
+        // [THEN] Verify Variant Code is still blank
+        SalesPriceList.Lines."Variant Code".AssertEquals('');
+        SalesPriceList.Close();
+    end;
+
