+    [Test]
+    procedure PostGenJournalWithTwoAllocationAccountsWith10DistributionLines()
+    var
+        GenJournalLine: array[3] of Record "Gen. Journal Line";
+        AllocationAccount: array[2] of Record "Allocation Account";
+        AllocAccountDistribution: Record "Alloc. Account Distribution";
+        BankAccount: Record "Bank Account";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GLEntry: Record "G/L Entry";
+        GLAccount: Record "G/L Account";
+        DocumentNo: Code[20];
+        TotalAmount: Decimal;
+        i: Integer;
+        j: Integer;
+    begin
+        // [SCENARIO 563854] When posting General Journal Lines with 2 Allocation Accounts each having 10 distribution lines,
+        // the line numbers should not collide and posting should succeed.
+        Initialize();
+
+        // [GIVEN] Create two Allocation Accounts, each with 10 distribution lines (Fixed type with Inherit from Parent).
+        for j := 1 to 2 do begin
+            AllocationAccount[j]."No." := LibraryUtility.GenerateGUID();
+            AllocationAccount[j]."Account Type" := AllocationAccount[j]."Account Type"::Fixed;
+            AllocationAccount[j].Name := AllocationAccount[j]."No.";
+            AllocationAccount[j].Insert(true);
+
+            for i := 1 to 10 do begin
+                AllocAccountDistribution.Init();
+                AllocAccountDistribution."Allocation Account No." := AllocationAccount[j]."No.";
+                AllocAccountDistribution."Line No." := i * 10000;
+                AllocAccountDistribution.Validate("Account Type", AllocAccountDistribution."Account Type"::Fixed);
+                AllocAccountDistribution.Validate("Destination Account Type", AllocAccountDistribution."Destination Account Type"::"Inherit from Parent");
+                AllocAccountDistribution.Validate(Share, 10);
+                AllocAccountDistribution.Insert(true);
+            end;
+        end;
+
+        // [GIVEN] Create a G/L Account for the journal lines.
+        GLAccount.Get(LibraryERM.CreateGLAccountNoWithDirectPosting());
+
+        // [GIVEN] Create a Bank Account for the balancing line.
+        LibraryERM.CreateBankAccount(BankAccount);
+
+        // [GIVEN] Generate Document No.
+        DocumentNo := LibraryUtility.GenerateGUID();
+
+        // [GIVEN] Create General Journal Batch.
+        CreateGeneralJournalBatch(GenJournalBatch);
+
+        // [GIVEN] Create General Journal line One with first Allocation Account.
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine[1],
+            GenJournalBatch."Journal Template Name",
+            GenJournalBatch.Name,
+            GenJournalLine[1]."Document Type"::" ",
+            GenJournalLine[1]."Account Type"::"G/L Account",
+            GLAccount."No.",
+            GenJournalLine[1]."Bal. Account Type"::"G/L Account",
+            '',
+            1000);
+
+        GenJournalLine[1].Validate("Document No.", DocumentNo);
+        GenJournalLine[1].Validate("Selected Alloc. Account No.", AllocationAccount[1]."No.");
+        GenJournalLine[1].Modify(true);
+        TotalAmount := 1000;
+
+        // [GIVEN] Create General Journal line Two with second Allocation Account.
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine[2],
+            GenJournalBatch."Journal Template Name",
+            GenJournalBatch.Name,
+            GenJournalLine[2]."Document Type"::" ",
+            GenJournalLine[2]."Account Type"::"G/L Account",
+            GLAccount."No.",
+            GenJournalLine[2]."Bal. Account Type"::"G/L Account",
+            '',
+            2000);
+
+        GenJournalLine[2].Validate("Document No.", DocumentNo);
+        GenJournalLine[2].Validate("Selected Alloc. Account No.", AllocationAccount[2]."No.");
+        GenJournalLine[2].Modify(true);
+        TotalAmount += 2000;
+
+        // [GIVEN] Create General Journal Line Three as Balancing Line.
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine[3],
+            GenJournalBatch."Journal Template Name",
+            GenJournalBatch.Name,
+            GenJournalLine[3]."Document Type"::" ",
+            GenJournalLine[3]."Account Type"::"Bank Account",
+            BankAccount."No.",
+            GenJournalLine[3]."Bal. Account Type"::"G/L Account",
+            '',
+            -TotalAmount);
+
+        GenJournalLine[3].Validate("Document No.", DocumentNo);
+        GenJournalLine[3].Modify(true);
+
+        // [WHEN] Posts General Journal Lines.
+        LibraryERM.PostGeneralJnlLine(GenJournalLine[3]);
+
+        // [THEN] Posted Gen. Journal Lines are balanced by Document No.
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'G/L Entries must be balanced');
+
+        // [THEN] 20 G/L entries should be created for the allocation (10 per allocation account).
+        GLEntry.SetRange("G/L Account No.", GLAccount."No.");
+        Assert.AreEqual(20, GLEntry.Count(), 'Expected 20 G/L entries for the two allocation accounts with 10 lines each');
+    end;
